content:
之前没有接触过这方面的应用（没想到分治 NTT 这么强大），故记录一下。

<!--more-->

首先我们考虑一个格路计数模型，即从 $(0,0)$ 出发，向右或向上走，要走到 $(n,m)$ ，但第 $i$ 列只存在行数不大于 $c_i$ 的点，$c_i$ 单调不降，且 $c_n = m$ ，求路径条数。

上述的网格是个阶梯状的图形，用分治 NTT 解决阶梯网格的格路计数是很经典的应用（虽然此前我从来没听说过）。

首先考虑 $n^2$ DP，这是简单的，即 $dp_{i,j} \to dp_{i+1,j},dp_{i,j} \to dp_{i,j+1}$。

但是直接这么做很难优化，本质上是因为这个 DP 没有明显的阶段性，即同一个 $i$ 内的所有 $j$ 都会互相转移。

我们修改 DP 状态，第一维记录 $x + y$，第二维记录 $y$ ，那么就会有 $dp_{k,j} \to dp_{k + 1,j},dp_{k,j} \to dp_{k+1,j+1}$。

为了避免在 $k > n$ 的时候还会有 $j \ge k - n$ 的限制，考虑从 $(n,0)$ 开始沿左上-右下方向把阶梯网格劈成两半，计算从 $(0,0)$ 和 $(n,m)$ 走到这条斜对角上的点 （$i + j = n$） 的方案数，容易发现这两个问题是对称的。

综合上述分析，我们将问题转化为，从 $(0,0)$ 出发，每次可以向右或向右上走一步，且在第 $i$ 列只存在行数不大于 $c_i$ 的点，走到最后一列每一个点的方案数。容易证明转化完后的 $c_i$ 仍然是不降的，且满足一个优秀的性质：$c_{x + 1} - c_x \le 1$。

事实上，转化后的 $c_i$ 就是 $x + y = i$ 的点的个数，就算这个阶梯形网格是个 $n \times m$ 的矩形，$c_{i + 1} - c_i$ 也不超过 $1$。

经过上述的转化之后，问题终于有了明显的分层，可以考虑优化转移了。

考虑一个 $dp_l$ 对 $dp_r$ 的贡献，设 $x = c_r - (r - l)$，我们发现，对于 $j \le x$，$dp_{l,j}$ 转移到 $dp_r$ 时不会受到 $c$ 的限制（因为 $c_{i + 1} - c_i \le 1$）。

![](/images/CF1770-2.png)

（图源自 @Alex_Wei，对于 $j \le x$ 的部分，它就算一路往上冲，也不会超过上图的红线。）

那么从 $dp_{l,j_1}(j_1 \le x)$ 转移到 $dp_{r,j_2}$ 的系数算起来就很容易了，就是 $\binom{r - l}{j_2 - j_1}$。

这是一个很明显的卷积形式，我们设 $F_i = dp_{l,i},G_i = dp_{r,i},H_i = \binom{r - l}{i}$，那么我们将 $F_{0 \dots x}$ 与 $H_{0 \dots r - l}$ 进行卷积， 将这一部分贡献加到 $G_{0 \dots c_r}$ 上。

对于 $j > x$ 的 $dp_{l,j}$，我们尝试将区间分为 $[l,mid]$ 和 $(mid,r]$ 递归处理，即先将左区间的贡献加到 $dp_{mid}$ 上，再用 $dp_{mid}$ 的一部分去更新 $dp_r$。

把这两部分的贡献加起来，所有 $k \in [l,r)$ 的 $dp_k$ 对 $dp_r$ 的贡献就计算完毕了。

考虑实现这么一个算法流程：

设 $Solve(l,r,\Delta,F)$ 表示当前还没确定 $dp$ 值的区间为 $(l,r]$，传入多项式的第 $i$ 项表示 $dp_{l,i + \Delta}$，返回多项式的第 $i$ 项表示 $dp_{r,i + \Delta}$ 。这也可以看作是让所有 $i \in [l,r]$ 的 $c_i$ 全部减去 $\Delta$，传入的 $F_i = dp_{l,i}$，返回的 $G_i = dp_{r,i}$。下文将采用这种视角进行叙述。

设 $x = c_r - (r - l)$，对于 $j \le x$，将 $F_{0 \dots x}$ 与 $H_{0 \dots r - l}$ 卷积，将得到的结果加到 $G_{0 \dots c_r}$ 上面。

对于 $j > x$，分治下放，设 $F' = F_{x + 1 \dots c_l}$，那么顺次执行 $F' \gets Solve(l,mid,\Delta + x + 1,F'),F' \gets Solve(mid,r,\Delta + x + 1,F')$。

将最后得到的 $F'$ 也加到 $G_{0 \dots c_r}$ 上面。然后返回 $G$ 即可。

对于边界，$r - l = 1$ 的处理是平凡的。

分析复杂度。对于下传的 $F'$，其长度显然不超过 $c_r - x = r - l$，也就是说，对于 $Solve(l,r,\Delta,F)$，$F$ 的长度不会超过当前分治区间的父区间的长度，即 $2(r - l)$。设 $n,m$ 同阶，则该算法复杂度与一般的分治 NTT 相同，为 $\Theta(n \log ^2 n)$。

---

终于可以说回原题了。

题意：给出一个括号串 $S$ ，设 $k$ 为最少需要删去的字符数使得原串是个合法括号串，求删去 $k$ 个字符后原串合法的方案数，对 $998244353$ 取模。

$1 \le |S| \le 5 \times 10^5$。

首先，我们要删去的字符一定形如 `))))((` ，即一段右括号再加上一段左括号。

我们考虑找到这个分界点。

把左括号看成 $1$,右括号看成 $-1$。考察这个序列的前缀和。

我们一定一个位置为 $\text{Special}$ 的，当且仅当它对应的数是前缀最小值。因为 $\text{Special}$ 位置的数一定是在它之前的位置的数的最小值减 $1$，所以每遇上一个 $\text{Special}$ 位置，我们就需要在这个位置或其之前删掉一个右括号。

那我们就将最后一个 $\text{Special}$ 位置，当作上述的分界线，在这个位置左边，我们只删右括号；在这个位置右边，我们只删左括号。

这两个部分是本质相同的，下文以删右括号的部分为例。

那么我们对于每个前缀，选中的右括号数一定不小于 $\text{Special}$ 位置的数量。

那么我们可以设 $dp_{i,j} (j \ge 0)$ 表示**前 $i$ 个右括号** ，选中的右括号数减去 $\text{Special}$ 位置的数量为 $j$ 的方案数。

如果 $i + 1$ 是个 $\text{Special}$ 位置，转移到 $dp_{i + 1,j/j - 1}$，否则转移到 $dp_{i + 1,j/j+1}$。

这看上去就挺格路计数的，可以套用上面的做法。因为限制只有 $j \ge 0$，我们甚至不需要记录 $\Delta$。

当然，还是稍有变形。具体地，记录 $[l,r]$ 中 $\text{Special}$ 位置的个数 $cnt$。那么对于 $j \ge cnt$，$dp_{l - 1,j}$ 转移到 $dp_{r,j + p - cnt}$ 就不受 $j \ge 0$ 限制的影响，转移系数为 $\binom{r - l + 1}{p}$ 。

对于 $j < cnt$ 的部分，递归下放去做即可，下放的多项式长度不会超过 $r - l + 1$，故复杂度为 $\Theta(n \log ^2 n)$。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 1 << 20,P = 998244353,G = 3;
inline int Add(int a,int b) { return (a + b >= P) ? (a + b - P) : (a + b);}
inline int Sub(int a,int b) { return (a < b) ? (a - b + P) : (a - b);}  
inline int qpow(int a,int b) { int res = 1;while(b) {if(b&1) res = 1ll * res * a % P;a = 1ll * a * a % P;b >>= 1;} return res;}
const int Gi = qpow(G,P - 2);
int n;
char s[N];
int Gs[N],Gs2[N];
int rev[N];

inline int GetLen(int x)
{
	int len = 1;
	while(len <= x) len <<= 1;
	return len;
}
inline void calc_rev(int len)
{
	for(int i = 0;i < len;i++)
	{
		rev[i] = rev[i >> 1] >> 1;
		if(i & 1) rev[i] |= len >> 1;
	}
}
int fac[N],ifac[N];
inline void init(int len)
{
	for(int i = 1;i < len;i <<= 1)
	{
		Gs[i] = Gs2[i] = 1;
		Gs[i + 1] = qpow(G,(P - 1) / (i << 1));
		Gs2[i + 1] = qpow(Gi,(P - 1) / (i << 1));
		for(int j = 2;j < i;j++)
			Gs[i + j] = 1ll * Gs[i + j - 1] * Gs[i + 1] % P,
			Gs2[i + j] = 1ll * Gs2[i + j - 1] * Gs2[i + 1] % P;
	}
	fac[0] = 1;
	for(int i = 1;i < len;i++) fac[i] = 1ll * fac[i - 1] * i % P;
	ifac[1] = 1;
	for(int i = 2;i < len;i++) ifac[i] = 1ll * ifac[P % i] * (P - P / i) % P;
	ifac[0] = 1;
	for(int i = 1;i < len;i++) ifac[i] = 1ll * ifac[i - 1] * ifac[i] % P;
}
inline int Binom(int n,int m) { if(n < 0 || m < 0 || n < m) return 0;return 1ll * fac[n] * ifac[m] % P * ifac[n - m] % P;}
inline void NTT(vector<int> &F,int len,int type)
{
	assert(F.size() <= len);
	F.resize(len);
	for(int i = 0;i < len;i++)
		if(i < rev[i]) swap(F[i],F[rev[i]]);
	for(int k = 1;k < len;k <<= 1)
		for(int j = 0;j < len;j += k + k)
			for(int i = 0;i < k;i++)
			{
				int cur = type == 1 ? Gs[k | i] : Gs2[k | i];
				int u = F[i | j],v = 1ll * cur * F[i | j | k] % P;
				F[i | j] = Add(u,v);
				F[i | j | k] = Sub(u,v);
			}
	if(type == -1)
		for(int i = 0,Inv = qpow(len,P - 2);i < len;i++)
			F[i] = 1ll * F[i] * Inv % P;
}
vector<int> t; // 存储每个要删的括号的标记状态
void Solve(int l,int r,vector<int> &f)
{
	if(l == r)
	{
		if(!t[l])
		{
			f.push_back(0);
			for(int i = f.size() - 1;i >= 1;i--)
				f[i] = Add(f[i],f[i - 1]);
		}
		else for(int i = 0;i < f.size() - 1;i++) f[i] = Add(f[i],f[i + 1]);
		return;
	}
	int mid = l + r >> 1,len = r - l + 1,cnt = 0;
	for(int i = l;i <= r;i++)
		cnt += t[i];
	vector<int> res(f.size() + (len - cnt),0);
	if(f.size() > cnt)
	{
		vector<int> A(f.size() - cnt,0),B(len + 1,0);
		for(int i = 0;i < f.size() - cnt;i++)
			A[i] = f[i + cnt];
		for(int i = 0;i <= len;i++)
			B[i] = Binom(len,i);
		int L = GetLen(f.size() + len - cnt);
		calc_rev(L);
		NTT(A,L,1);NTT(B,L,1);
		for(int i = 0;i < L;i++) A[i] = 1ll * A[i] * B[i] % P;
		NTT(A,L,-1);
		for(int i = 0;i < res.size();i++) res[i] = A[i];
	}
	vector<int> ff0(min((int)f.size(),cnt),0);
	for(int i = 0;i < ff0.size();i++) ff0[i] = f[i];
	Solve(l,mid,ff0);Solve(mid + 1,r,ff0);
	for(int i = 0;i < ff0.size();i++) res[i] = Add(res[i],ff0[i]);
	f = res;
}
int DoIt()
{
	if(t.empty()) return 1;
	vector<int> f(1,1);
	Solve(0,t.size() - 1,f);
	return f[0];
}
int main()
{
	scanf("%s",s + 1);
	n = strlen(s + 1);
	int cur = 0,lst = 0;
	init(GetLen(n * 2 + 2));
	for(int i = 1;i <= n;i++)
		if(s[i] == '(') ++cur;
		else { if(!cur) lst = i;else --cur;}
	cur = 0;
	for(int i = 1;i <= lst;i++)
		if(s[i] == '(') ++cur;
		else { if(!cur) t.push_back(1);else t.push_back(0),--cur;}
	int ans = DoIt();
	vector<int>().swap(t);cur = 0;
	for(int i = n;i > lst;i--)
		if(s[i] == ')') ++cur;
		else { if(!cur) t.push_back(1);else t.push_back(0),--cur;}
	ans = 1ll * ans * DoIt() % P;
	cout << ans << endl;
	return 0;
}
```

这道题加深了我对分治 NTT 的理解。

赛时想着用卷积处理散块，但不知道如何避免重复统计的问题，赛后看到题解做法大受震撼，故记录一下。有时一个观察能帮你省掉很多东西。

<!--more-->

我们先考虑固定右端点 $r$ ，计算所有左端点的答案。

一个关键但显然的观察是，$r$ 和 $r + m$ 的答案是相同的，这意味着我们只需计算 $1 \le l \le nm,1 \le r \le n$ 的答案，最后把答案乘 $m$ 即可。

设 $sum(p) = \sum_{i=1}^p b_i$ ，即 $b$ 序列的前缀和。如果 $nm$ 不大的话，我们大可以预处理出 $cnt[i]$ 表示满足 $sum(p) \bmod k = i$ 的 $p$ 的个数。然后扫描 $r$ ，每次先让 $cnt[sum(r)]$ 减 $1$，再提取出 $cnt[sum(r) + sum(n)]$ 作为 $r$ 的答案，再将 $cnt[sum(r) + sum(n)]$ 加 $1$ 。容易发现，上述过程正确地统计了所有 $l < r$ 和 $l > r$ 的子段，可以手算验证。

我们发现，上述做法的瓶颈在于，如何快速地预处理 $cnt$。

如果 $sum(n) \bmod k = 0$，处理起来比较容易。

否则，我们希望对于每个 $1 \le l \le n$，我们能把 $sum(l),sum(l + n),\dots sum(l + (m - 1)n)$ 的贡献一起加入到 $cnt$ 中，即需要对于 $t \in [0,m)$ ，令 $cnt[(sum(l) + t \cdot sum(n)) \bmod k]$ 自增 $1$。事实上，考虑一张图，对于每个点 $i$，连边 $(i,(i + sum(n)) \bmod k)$ ，最后会形成一个长度为 $k$ 的环（因为 $k$ 是质数），那么我们的操作相当于对环上连续的一段进行区间加。维护差分数组即可做到 $\Theta(n + k)$。

事实上，对于 $k$ 不是质数的情况，上述做法也是可行的，只不过可能会形成若干个环，我们要对每个环分开考虑。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 2e5 + 5,P = 1e9 + 7;
int n,m,k,sum[N];
int cnt[N];
int Id[N]; // 环上各点的编号
int dif[N]; // 差分数组
int main()
{
	cin >> n >> m >> k;
	for(int i = 1;i <= n;i++)
		cin >> sum[i],(sum[i] += sum[i - 1]) %= k;
	int sall = 1ll * sum[n] * m % k;
	int sn = sum[n];
	if(!sn)
	{
		int res = 0;
		for(int i = 1;i <= n;i++) (res += cnt[sum[i]]++) %= P;
		int ans = (1ll * ((res << 1ll) + n) % P * m % P * m % P - (1ll * n * m % P) + P + 1) % P;
		cout << ans << endl;
		return 0;
	}
	Id[0] = 1;
	for(int i = sn,j = 2;i;i = (i + sn) % k,++j)
		Id[i] = j;
	for(int i = 1;i <= n;i++)
	{
		int vl = sum[i],vr = (sum[i] + 1ll * m * sn % k) % k; // [vl,vr)
		vl = Id[vl];vr = Id[vr];
		(dif[1] += m / k) %= P;
		if(vl <= vr) dif[vl]++,dif[vr]--;
		else dif[vl]++,dif[1]++,dif[vr]--;
	}
	for(int i = 1;i <= k;i++)
		(dif[i] += dif[i - 1]) %= P;
	// for(int i = 1;i <= n;i++) printf("%d ",sum[i]);printf("\n");
	// for(int i = 0;i < k;i++) printf("%d ",Id[i]);printf("\n");
	// for(int i = 1;i <= k;i++) if(dif[i]) printf("%d,%d ",i,dif[i]);printf("\n");
	int ans = 0;
	//(dif[Id[sall]] += 1) %= P;
	for(int r = 1;r <= n;r++)
	{	
		(dif[Id[sum[r]]] += P - 1) %= P;
		(ans += dif[Id[(sum[r] + sall) % k]]) %= P;
		(dif[Id[(sum[r] + sall) % k]] += 1) %= P;
	}
	ans = 1ll * ans * m % P;
	if(!sall) ans = (ans + 1) % P;
	cout << ans << endl;
	return 0;
}
```

这题推出平方的转移式不难，但是进一步优化需要技巧。

<!--more-->

首先把 ”不全红“ 和”不全蓝“的限制去掉。

其次，对于一个完全图，它如果不 红边连通，蓝边连通。

这个证明是容易的，假设一个完全图有两个点集 $A,B$，$A$ 与 $B$ 之间没有红边，那么对于任意 $a \in A$，$b \in B$，$(a,b)$ 之间都会有一条蓝边，那么这个图显然会被蓝边连通。

那我们只需要保证红蓝不同时连通即可。

设 $f_n$ 表示一个 $n$ 个点的完全图由红边连通的方案数，那么 $ans = 2f_n - 2$。

考虑转移，既然这张图蓝边不连通，那么我们枚举 $1$ 号点所在的蓝边连通块大小，设为 $i$，那么会有 $\binom{n - 1}{i-1}$ 种方案选出这个连通块，块内的方案数是 $f_i$，块外的方案数是 $f_{n-i}$ ，块内与块外之间的边必须都是红边，故系数为 $1$。另外，如果 $n - i > 1$，方案数还要乘 $2$，因为块外的图既可以红连通，也可以蓝连通。

直接转移即可通过 F1。

考虑优化转移的复杂度，把转移式写出来。
$$
f_i = 2\sum_{j=1}^{i-2} \binom{i-1}{j-1}f_jf_{i-j} + f_1f_{i-1}\binom{i-1}{i-2} \\
$$
写得好看一些：
$$
f_i = 2\sum_{j=1}^{i-1} \binom{i-1}{j-1}f_jf_{i-j} - (i -1)f_{i-1}
$$
令
$$
f'_i = \sum_{j=1}^{i-1} \binom{i-1}{j-1}f_jf_{i-j}
$$
那么 $f_i = 2f'_i - (i - 1)f_{i-1}$。

把组合数拆开：
$$
\dfrac{f'_i}{(i-1)!} = \sum_{j=1}^{i-1} \dfrac{f_j}{(j-1)!}\dfrac{f_{i-j}}{(i-j)!}
$$
设 $F_i = \dfrac{f_i}{(i-1)!},G_i = \dfrac{f_i}{i!}$。

那么 $f'_i = \sum_{j=1}^{i-1}F_jG_{i-j}$

这看上去就像分治 FFT 的式子，但我们发现 $F$ 和 $G$ 都需要由卷积的结果推出，而一般的分治 FFT 中，$G$ 这个位置放的是个已知序列。

考虑一般的分治 FFT,我们是用  $F_{[l,mid]}$ 与 $G_{[1,r-l]}$ 进行卷积，并将结果加到右区间对应的位置。

考虑这个方法什么时候会出问题，这种情况会出现当且仅当 $r - l > mid$ ，即 $2r - 2l > l + r$，即 $r > 3l$。

这种情况只会在 $l = 1$ 时出现，因为在分治树上第一次往右走时，就有 $r < 2l$，此后 $l$ 不降，$r$ 不增，自然也不会出问题。

考虑把分治 FFT 的贡献拆成三部分：
$$
\sum_{j=i-mid}^{mid} F_jG_{i-j} + \sum_{j=mid+1}^{i-1}F_jG_{i-j} + \sum_{j=1}^{i-mid-1}F_jG_{i-j}
$$
第一部分的贡献可以在 $[1,r]$ 那里就算完了，第二部分和第三部分的贡献形式是相同的，可以在 $l \ne 1$ 的区间里一起计算这两类贡献。

具体的可以看代码，时间复杂度 $\Theta(n \log ^2n)$。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 2e5 + 5,P = 998244353,GG = 3;
inline int Add(const int &a,const int &b) { return (a + b >= P) ? (a + b - P) : (a + b);}
inline int Sub(const int &a,const int &b) { return (a < b) ? (a - b + P) : (a - b);}
inline int qpow(int a,int b) { int res = 1;while(b) {if(b&1) res = 1ll * res * a % P;a = 1ll * a * a % P;b >>= 1;} return res;}
const int Gi = qpow(GG,P - 2);
int n;
int Gs[N],Gs2[N],rev[N];
inline int GetLen(int x)
{
	int len = 1;
	while(len <= x) len <<= 1;
	return len;
}
inline void calc_rev(int len)
{
	for(int i = 0;i < len;i++)
	{
		rev[i] = rev[i >> 1] >> 1;
		if(i & 1) rev[i] |= len >> 1;
	}
}
int fac[N],ifac[N];
inline void init(int len)
{
	for(int i = 1;i < len;i <<= 1)
	{
		Gs[i] = Gs2[i] = 1;
		Gs[i + 1] = qpow(GG,(P - 1) / (i << 1));
		Gs2[i + 1] = qpow(Gi,(P - 1) / (i << 1));
		for(int j = 2;j < i;j++)
			Gs[i + j] = 1ll * Gs[i + j - 1] * Gs[i + 1] % P,
			Gs2[i + j] = 1ll * Gs2[i + j - 1] * Gs2[i + 1] % P;
	}
	fac[0] = 1;
	for(int i = 1;i <= len;i++) fac[i] = 1ll * fac[i - 1] * i % P;
	ifac[1] = 1;
	for(int i = 2;i <= len;i++) ifac[i] = 1ll * ifac[P % i] * (P - P / i) % P;
	ifac[0] = 1;
	for(int i = 1;i <= len;i++) ifac[i] = 1ll * ifac[i - 1] * ifac[i] % P;
}
inline void NTT(int *F,int len,int type)
{
	for(int i = 0;i < len;i++)
		if(i < rev[i]) swap(F[i],F[rev[i]]);
	for(int k = 1;k < len;k <<= 1)
		for(int j = 0;j < len;j += k + k)
			for(int i = 0;i < k;i++)
			{
				int cur = type == 1 ? Gs[k | i] : Gs2[k | i];
				int u = F[i | j],v = 1ll * cur * F[i | j | k] % P;
				F[i | j] = Add(u,v);
				F[i | j | k] = Sub(u,v);
			}
	if(type == -1)
		for(int i = 0,Inv = qpow(len,P - 2);i < len;i++)
			F[i] = 1ll * F[i] * Inv % P;
}
int A[N],B[N];

int f[N],F[N],G[N];
void cdq(int l,int r)
{
	if(l == r)
	{
		if(l > 1)
		{
			f[l] = 2ll * f[l] * fac[l - 1] % P;
			f[l] = Sub(f[l],1ll * (l - 1) * f[l - 1] % P);
			F[l] = 1ll * f[l] * ifac[l - 1] % P;
			G[l] = 1ll * f[l] * ifac[l] % P;
		}
		return;
	}
	int mid = l + r >> 1;
	cdq(l,mid);
	if(l == 1)
	{
		int len = GetLen((mid - l + 1) + (mid - l + 1)); // 第一部分
		for(int i = 0;i < len;i++) A[i] = B[i] = 0;
		for(int i = 0;i <= mid - l;i++)
			A[i] = F[i + 1],B[i] = G[i + 1];
		calc_rev(len);
		NTT(A,len,1);NTT(B,len,1);
		for(int i = 0;i < len;i++) A[i] = 1ll * A[i] * B[i] % P;
		NTT(A,len,-1);
		for(int i = mid + 1;i <= r;i++)
			f[i] = Add(f[i],A[i - 2]);
	}
	else // 第二部分和第三部分
	{
		int len = GetLen((r - l + 1) + (mid - l + 1));
		for(int i = 0;i < len;i++) A[i] = B[i] = 0;
		for(int i = 0;i < r - l;i++)
			A[i] = F[i + 1];
		for(int i = 0;i <= mid - l;i++)
			B[i] = G[i + l];
		calc_rev(len);
		NTT(A,len,1);NTT(B,len,1);
		for(int i = 0;i < len;i++) A[i] = 1ll * A[i] * B[i] % P;
		NTT(A,len,-1);
		for(int i = mid + 1;i <= r;i++)
			f[i] = Add(f[i],A[i - l - 1]);
		for(int i = 0;i < len;i++) A[i] = B[i] = 0;
		for(int i = 0;i < r - l;i++)
			A[i] = G[i + 1];
		for(int i = 0;i <= mid - l;i++)
			B[i] = F[i + l];
		calc_rev(len);
		NTT(A,len,1);NTT(B,len,1);
		for(int i = 0;i < len;i++) A[i] = 1ll * A[i] * B[i] % P;
		NTT(A,len,-1);
		for(int i = mid + 1;i <= r;i++)
			f[i] = Add(f[i],A[i - l - 1]);
	}
	cdq(mid + 1,r);
}
int main()
{
	cin >> n;
	f[1] = F[1] = G[1] = 1;
	int len = GetLen(n * 2);
	init(len);
	cdq(1,n);
	cout << ((f[n] - 1) * 2ll) % P << endl;
	return 0;
}
```

人类智慧题，对于这种题确实不太会。接受现实，多加练习（

<!--more-->

这题一眼看过去没有什么思路或性质。需要字典序最小，我们只能从最小的字符开始考察，设其为 $a$。

我们的首要目标是在最后最大化最开头那段 $a$ 的长度。

如果在翻转之前，有一段 $a$ 处在 $S$ 的末尾，那么翻转过后，其会变成原来的两倍长，如果处在其它地方，你只能多得到一段长度相等的 $a$。

所以，对于 $k > \lceil \log_2 n \rceil + 1$ ，只需输出 $n$ 个 $a$ 即可。

对于剩下的情况，我们可以用开头的一次操作把最长的 $a$ 放到串的末尾，然后不断倍长，在最后一次操作时把这段 $a$ 放在结果串的开头。

接下来我们要让 $a$ 后面的那一段的字典序最小。

设那段最长的 $a$ 为 $A$，它前面的串为 $B$。我们先用一次操作把 $BA$ 提到 $S$ 的最后，再一次操作后变为 $BAAB$，容易发现，新的串必然是 $BA^2$ 的一段后缀，如此下去，最后的串必然是 $A^{2^{k-1}}B^R$ 的一段前缀，我们只需找出字典序最小的 $B^R$。

有意思的地方是，由于 $SS^R$ 为回文串，只要 $BA$ 在 $S$ 中出现，$AB^R$ 一定会在 $S^R$ 中出现，那么我们找字典序最小的 $AB^R$ ，只需在 $SS^R$ 中找到字典序最小的长度为 $n$ 的子串即可。这个可以 $\Theta(n^2)$ 完成。

上面的做法也统一了 $k = 1$ 的情况，最终的时间复杂度为 $\Theta(n^2)$。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 5e3 + 5;
int n,k;
char s[N << 1];
char ans[N];
inline void Useans(int p)
{
	for(int i = 1;i <= n;i++)
		ans[i] = s[p + i - 1];
}
int fir;
inline void Check(int p)
{
	if(!fir) Useans(p),fir = true;
	for(int i = 1;i <= n;i++)
	{
		if(ans[i] < s[i + p - 1]) return;
		if(ans[i] > s[i + p - 1]) return Useans(p);
	}
}
int main()
{
	cin >> n >> k;
	cin >> (s + 1);
	if(k >= 15)
	{
		char c = 'z';
		for(int i = 1;i <= n;i++) c = min(c,s[i]);
		for(int i = 1;i <= n;i++) putchar('c');
		putchar('\n');
		return 0;
	}
	for(int i = 1;i <= n;i++) s[n * 2 + 1 - i] = s[i];
	for(int i = 1;i <= n + 1;i++) Check(i);
	int mx = 0;
	for(int i = 1;i <= n + 1;i++)
		if(ans[i] == ans[1]) ++mx;
		else break;
	int len = mx << (k - 1);
	for(int i = 1;i <= len;i++) putchar(ans[1]);
	for(int i = len + 1;i <= n;i++) putchar(ans[i - len + mx]);
	putchar('\n');
	return 0;
}
```

这题增进了我对概率论的一些理解。

<!--more-->

设当前局面为 $S$ 。

容易发现，在一次 $S_1 \to S_2 \to \dots \to S_k $ 的过程中，大部分的题目都不会对 $S$ 产生影响。

我们称对 $S$ 序列产生影响的题目是 "关键的"，显然，夹在两个“关键”题目之间的非关键题目可以任意排列，它们不会对概率产生影响。（这是比较重要的一点）。

那我们的任务主要就是，在确定 $S$ 序列的过程中，顺便确定 "关键题目的排列"。

$S$ 只会越变越小，这给了我们 DP 的状态和方式：设 $f_S$ 表示到达局面 $S$ 的概率，转移则枚举子集。

枚举从 $S$ 转到 $T$ 是因为哪道题目，设为 $s_i$，那么有 $s_i \cap S = T$。设能够改变 $S$ 的题目有 $c$ 个（即满足 $S \cap s_j \ne \varnothing,S$  的 $j$ 的个数），那么这 $c$ 个题目显然不会在 $S$ 以前的地方出现（否则当前局面就不是 $S$ 了）。在这一类题目中，我们要求当前枚举的 $s_i$ 最早出现，对应的概率就是 $\dfrac{1}{c}$，那么就会有 $\dfrac{f_S}{c} \to f_{S \cap s_i}$。

这显然过不去，但是注意到后继局面（即 $S \cap s_i$） 相同的转移可以合并，故设 $g_{S,T}$ 表示满足 $s_i \cap S = T$  的 $i$ 的个数，那么 $c = \sum\limits_{T \ne \varnothing,S} g_{S,T}$，上述转移就改写为 $\dfrac{f_Sg_{S,T}}{c} \to f_T$。

$g_{S,T}$ 可以递推预处理，具体地，取任意不属于 $S$ 的元素 $p$，有 $g_{S,T} = g_{S \cup \{p\},T} + g_{S\cup \{p\},T \cup \{p\}}$。

上述工作都可以在 $\Theta(3^m)$ 时间内完成，故总时间复杂度为 $\Theta(3^m)$，可以通过。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 2e5 + 5,M = 1 << 17;
typedef double db;
vector<int> g[M];
db f[M],ans;
int n,m;
int cnt[M];
int pop[M];
int cc[M];
#define lowbit(x) ((x)&(-(x)))
int tid[M];
int main()
{
	cin >> n >> m;
	for(int i = 1;i <= n;i++)
	{
		string st;int S = 0;
		cin >> st;
		for(int j = 0;j < m;j++)
			if(st[j] == '1') S |= (1 << j);
		++cnt[S];
	}
	for(int i = 1;i < (1 << m);i++) pop[i] = pop[i >> 1] + (i & 1);
	for(int S = (1 << m) - 1;S >= 0;--S)
	{
		g[S].resize(1 << pop[S]);
		if(S + 1 == (1 << m))
		{
			for(int T = S & (S - 1),i = 0;T;T = (T - 1) & S,++i)
				g[S][i] = cnt[T],cc[S] += cnt[T];
			continue;
		}
		int from = S | lowbit(((1 << m) - 1) ^ S),p = lowbit(((1 << m) - 1) ^ S);
		for(int T = from & (from - 1),i = 0;T;T = (T - 1) & from,++i)
			tid[T] = i;
		for(int T = S & (S - 1),i = 0;T;T = (T - 1) & S,++i)
			g[S][i] = g[from][tid[T]] + g[from][tid[T | p]],cc[S] += g[S][i];
	}
	f[(1 << m) - 1] = 1;
	for(int S = (1 << m) - 1;S;--S)
	{
		if(cc[S] == 0)
		{
			if(S & 1) ans += f[S];
			continue;
		}
		for(int T = S & (S - 1),i = 0;T;T = (T - 1) & S,++i)
			f[T] += f[S] * g[S][i] / cc[S];
	}
	printf("%.9lf\n",ans);
	return 0;
}
```

本题就当是对 Slope trick 的入门了。

<!--more-->

首先考虑 $\sum w$ 不大的情况。

设 $f_i(x)$ 表示在 $i$ 子树内，点燃时间为 $x$ 的最小代价。

那么考虑合并 $f_i$ 和一个儿子 $f_{son}$ ，则有 $f_i(x) \gets f_i(x) +  \min_{y \le x} \{f_{son}(y) + |w - x + y|\}$ 。（$w$ 是 $i$ 与 $son$ 之间的边权）

我们令 $G_{son}(x) = \min_{y \le x} \{f_{son}(y) + |w - x + y|\}$。

可以证明，$f_i(x)$ 是关于 $x$ 的下凸函数，且每一段的斜率均为整数。

设 $[L,R]$ 表示 $f_{son}(x)$ 斜率为 $0$ 的那一段的左右端点的横坐标，那么 $G_{son}(x)$ 变化如下：
$$
G_{son}(x) = \begin{cases} f_{son}(x) + w ,x \lt L \\
f_{son}(L) + w - (x - L),L \le x \lt L + w \\
f_{son}(L),L + w \le x \lt R + w \\
f_{son}(x) + (x - R) - w,x \ge R + w \\
\end{cases}
$$
 具体分析如下：

对于第一种情况：因为在 $x < L$ 处 ，$f_{son}(x)$ 的斜率小于等于 $-1$，即修改 $son$ 以下的边的代价 $\ge 1$，那肯定不如直接修改 $w$ （代价恰为 $1$），所以在这里直接把 $w$ 修改到 $0$，然后取出在 $x$ 点的函数值。

对于第二种情况：函数在 $f_{son}(L)$ 处取到最小值，我们跟第一种情况的理由一样，能够修改 $w$ 就别修改 $f_{son}(x)$ 中的 $x$ ，所以 $f_{son(x)}$ 中的 $x$ 一定 $\ge L$，而为了让 $w$ 修改的代价尽量小，我们直接把 $w$ 拉到 $x - L$ 。这样就是最优的了。

第三种情况较为简单，第四种情况与第一种类似，就不再赘述。

对于这种斜率为整数的下凸壳，我们可以通过维护拐点和最右边的直线来表示这个凸壳。

![](/images/P3642-1.png)

就像上图，我们只需维护所有的红点和红线即可。

我们默认每三个相邻拐点所表示的两条直线的斜率差都是 $1$，如果不是，那我们就多次加入同一个拐点。

如何求一个点 $L$ 的函数值 $f_{son}(L)$ 呢？因为拐点的斜率差都是 $1$，我们用 $f(0)$ 减去在 $L$ 之前的所有拐点的横坐标即可。

如何执行 $f_i(x) \gets f_i(x) + G_{son}(x)$ 呢？还是因为拐点序列的性质，我们直接把二者的拐点序列按顺序拼接起来即可。



现在我们有了这个凸壳模型，我们考虑上面的操作是如何把 $F_{son}(x)$ 变为 $G_{son}(x)$ 的。

首先，把 $L$ 左边的部分向上平移 $w$，然后把 $[L,R]$ 这一部分整体向右平移 $w$，并在 $[L,L + w]$ 处插入一条斜率为 $-1$ 的直线，把原函数 $> R + w$ 的部分的斜率都变为 $1$。

注意到函数的斜率最大值也只有 $1$，我们甚至不需要“维护那条红线”，处理所有的拐点即可。

考虑这些操作怎么办：

1. 向上平移 $w$，这等价于 $f(0) \gets f(0) + w$，而 $f(0)$ 不论是从这里来看，还是从定义上看，都显然是所有边权的和，所以这个很简单。
2. 把大于 $R + w$ 的部分的斜率都变为 $1$。这个可以在所有的 $G_{son}(x)$ 都并入 $f_i(x)$ 之后再行处理。注意到每个 $G_{son}(x)$ 有且仅有一个斜率为正的拐点 $R + w$，假设 $i$ 的儿子有 $k_i$ 个，那么合并完之后就有 $k_i$ 个斜率为正的拐点，那么弹出 $k_i - 1$ 个最大的拐点即可。
2. 把 $[L,R]$ 向右平移一个 $w$ ，这个只需要删除拐点 $L,R$，加入拐点 $L + w,R + w$ 即可。
3. 插入一条斜率为 $-1$ 的直线，这个在第三项中其实就已经处理完了。

以上操作都可以用一个可合并的大根堆维护，写个左偏树即可。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 6e5 + 5;
typedef long long ll;
struct node{
	int lc,rc,dis;
	ll val;
}tr[N];
int Merge(int x,int y)
{
	if(!x || !y) return x + y;
	if(tr[x].val < tr[y].val) swap(x,y);
	tr[x].rc = Merge(tr[x].rc,y);
	if(tr[tr[x].lc].dis < tr[tr[x].rc].dis) swap(tr[x].lc,tr[x].rc);
	tr[x].dis = tr[tr[x].rc].dis + 1;
	return x;
}
inline int Pop(int x) { return Merge(tr[x].lc,tr[x].rc);}
int rt[N];
int n,m;
int fa[N],C[N],sons[N];
int main()
{
	cin >> n >> m;
	for(int i = 2;i <= n + m;i++)
		cin >> fa[i] >> C[i],++sons[fa[i]];
	ll ans = 0;
	int tot = 0;
	for(int i = n + m;i > 1;i--)
	{
		ll l = 0,r = 0; // 维护斜率为 0 的那些线段
		if(i <= n) // 非叶
		{
			while(--sons[i]) rt[i] = Pop(rt[i]);
			r = tr[rt[i]].val;rt[i] = Pop(rt[i]);
			l = tr[rt[i]].val;rt[i] = Pop(rt[i]);
		}
		tr[++tot].val = l + C[i];
		tr[++tot].val = r + C[i];
		rt[i] = Merge(rt[i],Merge(tot,tot - 1));
		rt[fa[i]] = Merge(rt[fa[i]],rt[i]);
	}
	for(int i = 2;i <= n + m;i++) ans += C[i]; // f(0)
	while(sons[1]--) rt[1] = Pop(rt[1]);
	while(rt[1]) ans -= tr[rt[1]].val,rt[1] = Pop(rt[1]);
	cout << ans << endl;
	return 0;
}
```

这完全是能力范围内的题。日常做题时还是要多想一想，多尝试尝试，多用几种不同的解法，因为考场上没有看题解的机会。

<!--more-->

首先这题看上去就很 $\min-\max$ 容斥，先套上去试一下。

$$ E(\max(S)) = \sum_{T \subseteq S,T \ne \varnothing} (-1)^{|T|-1} E(\min(T))$$。

考虑一个 $E(\min(T))$ 该怎么算。

首先，$T$ 内的问题无法完全与 $T$ 外的独立开来，因为每次操作是在所有数之间进行的，这会涉及到一个条件概率的问题。

这里有一个比较巧妙的转化，即 **第一次到达停止状态的时间是 所有到达停止状态之前的状态的概率乘上停留在该状态的期望时间 之和**（我们熟知的等式 $E(x) = \sum_{i \ge 0} P(X > i)$ 就是在所有状态的期望停留时间均为 $1$ 时的特例）。

证明并不难，也与 $E(x) = \sum_{i \ge 0} P(X > i)$ 的证明基本一致。（不过这一点倒是增进了我对这个式子的理解）。

那么每个状态的期望停留时间怎么算？

考虑什么时候会“停留”，即我们一次操作选到了集合 $T$ 之外的点。

显然这个量只与 $\sum_{i \in T} a_i$ 有关。

更具体地，设 $P$ 表示集合 $T$ 中某个状态的期望停留时间，设 $S = \sum_{i=1}^na_i$，那么会有 $P = \dfrac{S - \sum_{i \in T} a_i }{S}P + 1$ ，即 $P = \dfrac{S}{\sum_{i \in T}a_i}$。

考察另外一个部分，即到达某个状态的概率，设 $c_i \in [0,b_i)$ 表示 $i (i \in T)$ 在该状态中的出现次数。

那么概率就是 
$$
\binom{\sum c}{c_1,c_2,\dots,c_{|T|}}\prod_{i \in T} (\dfrac{A_i}{\sum_{j \in T}A_j})^{c_i} 
$$
设 $A = \sum_{i \in T} a_i,C = \sum_{i \in T} c_i$。

那么将上式化简可得 $\dfrac{C!}{A^C}\prod \dfrac{A_i^{c_i}}{c_i!}$。

代入 $\min-\max$ 的式子，那么原式可化为
$$
\sum_{T \subseteq S,T \ne \varnothing} (-1)^{|T|-1} \dfrac{\sum_{i=1}^na_i}{A} \dfrac{C!}{A^C} \prod_{i \in T} \dfrac{A_i^{c_i}}{c_i!}
$$

中间两个分式只与 $A$ 和 $C$ 有关，而后面的 $\prod$ 显然可以 DP。

设 $f_{i,j,k}$ 表示考察前 $i$ 个数，$A = j$ 且 $C = k$ 的 $(-1)^{|T|-1}\prod_{i \in T} \dfrac{A_i^{c_i}}{c_i!}$ 之和，转移如下：

$$ f_{i,j,k} = f_{i-1,j,k} - \sum_{c < b_i} f_{i-1,j-a_i,k-c}\dfrac{A_i^c}{c!}$$。

因为第二维是个背包状物，故直接枚举 $c$ 就可以做到 $\Theta(AB^2)$ 了。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 4e2 + 5,P = 998244353;
int n;
int a[N],b[N];
int fac[N],ifac[N];
int f[N][N][N];
inline void Plus(int &x,const int &y) { x += y;if(x >= P) x -= P;}
inline void Minus(int &x,const int &y) { x -= y;if(x < 0) x += P;}
inline int qpow(int a,int b) { int res = 1;while(b) {if(b&1) res = 1ll * res * a % P;a = 1ll * a * a % P;b >>= 1;} return res;}
inline void init(int n)
{
	fac[0] = 1;
	for(int i = 1;i <= n;i++) fac[i] = 1ll * fac[i - 1] * i % P;
	ifac[1] = 1;
	for(int i = 2;i <= n;i++) ifac[i] = 1ll * (P - P / i) * ifac[P % i] % P;
	ifac[0] = 1;
	for(int i = 1;i <= n;i++) ifac[i] = 1ll * ifac[i - 1] * ifac[i] % P;
}
int sumA = 0,sumB = 0;
int main()
{
	cin >> n;
	for(int i = 1;i <= n;i++) cin >> a[i] >> b[i],sumA += a[i],sumB += b[i];
	init(sumB);
	int sum = 0;
	f[0][0][0] = P - 1;
	for(int i = 1;i <= n;i++)
	{
		for(int j = a[i];j <= sumA;j++)
		{
			for(int k = 0;k <= sum;k++)
				for(int c = 0,now = 1;c < b[i];++c)
				{
					Minus(f[i][j][k + c],1ll * f[i - 1][j - a[i]][k] * now % P * ifac[c] % P);
					now = 1ll * now * a[i] % P;	
				}
		}
		sum += b[i];
		for(int j = 0;j <= sumA;j++)
			for(int k = 0;k <= sum;k++)
				Plus(f[i][j][k],f[i - 1][j][k]);
	}
	int ans = 0;
	for(int sa = 0;sa <= sumA;sa++)
		for(int sc = 0;sc <= sumB;sc++)
			Plus(ans,1ll * fac[sc] * sumA % P * qpow(qpow(sa,P - 2),sc+1) % P * f[n][sa][sc] % P);
	cout << ans << endl;
	return 0;
}
