<!--more-->

按值域从小到大 DP，每次考虑插入 $A_i$ 个 $i$。

假设已经插入的数形成了 $j$ 个连续段，显然，除了最左和最右的连续段，剩下的段的两端都是 $i - 1$（不然就无法满足相邻位置差为 $1$）

这提示我们最左边和最右边有一些特殊性。

事实上，如果最左边是 $i - 1$，那么当前的 $i$ 还可以插到左边，否则不行。右边同理。

那么我们设 $dp_{i,j,u,v}$ 表示当前做到 $i$，一共形成了 $j$ 个连续段，最左边是不是 $i$，最右边是不是 $i$。

转移有两个方面，第一是 $j$ 的变化，第二是转移系数。

如果我们想在最左和最右都填上 $i$ 的话，我们首先会把 $2j$ 个 $i$ 填在每个连续段的两侧，然后剩余的 $A_i -2j$ 个 $i$ 会贡献 $A_i - 2j$ 个连续段，总段数就是 $A_i - j$。

如果想在某几侧不填上 $i$ 的话，道理是一样的，将结果 $+1$ 或 $+2$ 即可。

考察转移系数，还是以 $u = v = 1$ 为例，这时一共会有 $j + 1$ 个空隙，每个空隙都必须有数，这就是个插板法，方案数为 $\binom{A_i - 1}{j}$。

直接这么做，看上去可以达到平方复杂度，但是，我们发现 $j$ 的变化方法较为单一，它只有可能在每轮中由 $j$ 变为 $A_i - j$，或在 $u$ 或 $v$ 变化时加上 $1$ 或者 $2$。

我们处理出 $cur_i$ 表示如果前 $i$ 轮，每轮都在两边放数，会有几个连续段（显然有 $cur_i = a_i - cur_{i-1}$）。

那么 $j$ 的取值只会在 $cur_i$ 附近，取 $[cur_i - 2,cur_i + 4]$ 即可。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 2e5 + 5,P = 998244353;
inline void Plus(int &x,const int &y) { x += y;if(x >= P) x -= P;}
int n,a[N],cur[N];
int dp[N][7][2][2];
int fac[N],ifac[N];
inline void init(int n)
{
	fac[0] = 1;
	for(int i = 1;i <= n;i++) fac[i] = 1ll * fac[i - 1] * i % P;
	ifac[1] = 1;
	for(int i = 2;i <= n;i++) ifac[i] = 1ll * ifac[P % i] * (P - P / i) % P;
	ifac[0] = 1;
	for(int i = 1;i <= n;i++) ifac[i] = 1ll * ifac[i - 1] * ifac[i] % P;
}
inline int C(int n,int m) { if(n < 0 || m < 0 || n < m) return 0;return 1ll * fac[n] * ifac[m] % P * ifac[n - m] % P;}
int main()
{
	cin >> n;
	for(int i = 1;i <= n;i++)
		cin >> a[i];
	cur[1] = a[1];
	dp[1][2][1][1] = 1;
	init(2e5);

	for(int i = 2;i <= n;i++)
	{
		cur[i] = a[i] - cur[i - 1]; // 如果两边都不放 i,会有多少对相邻的 i
		for(int j = 0;j <= 6;j++)
			for(int u = 0;u <= 1;u++)
			for(int v = 0;v <= 1;v++)
			if(dp[i - 1][j][u][v])
			{
				for(int p = 0;p <= u;p++)
				for(int q = 0;q <= v;q++)
				{
					int val = dp[i - 1][j][u][v],c = cur[i - 1] + j - 2; // c 表示实际有多少对相邻的 i
					if(p == 0 && q == 0)
						Plus(dp[i][6 - j][p][q],1ll * val * C(a[i] - 1,c - 2) % P); // 4 - j : a - 原段数 + 2
					if(p == 1 && q == 1 && j <= 4)
						Plus(dp[i][4 - j][p][q],1ll * val * C(a[i] - 1,c) % P); // 2 - j: a - 原段数
					if(p + q == 1 && j <= 5)
						Plus(dp[i][5 - j][p][q],1ll * val * C(a[i] - 1,c - 1) % P);
				}
			}
		for(int j = 0;j <= 6;j++)
			for(int u = 0;u <= 1;u++)
				for(int v = 0;v <= 1;v++)
					printf("f[%d][%d][%d][%d]=%d\n",i,cur[i] + j - 2,u,v,dp[i][j][u][v]);
	}
	int ans = 0;
	for(int i = 0;i <= 6;i++)
		for(int u = 0;u <= 1;u++)
			for(int v = 0;v <= 1;v++)
				if(cur[n] + i - 2 == 1)
					Plus(ans,dp[n][i][u][v]);
	cout << ans << endl;
	return 0;
}
```

要打开此题的突破口，Kruskal 和拆贡献都要想到。我只想到了 Kruskal ，所以寄了。大概在此种计数最优方案的题中，以已有的最优化算法为基础，进行贡献拆解是常见的套路。

类似的题还有：P4517 JSOI2018 防御网络。

<!--more-->

对于一张确定的图，这道题是要我们求出边权和最大的基环树森林。

而基环树森林与生成树是类似的，可以套用 Kruskal 算法的模型，将边从大到小排序，如果加入一条边仍满足条件就加进去（因为 “基环树森林” 的限制可以像“生成树”一样导出一个拟阵，所以我们才能贪心地加边）。

那么我们考察某一条边 $(u,v,w)$ 的贡献，看它什么时候会被加进去。

假设我们已经做完了边权大于 $w$ 的所有边，那么这条边就面临两种产生贡献的情况：

1. $u,v$ 连通，且该连通块是棵树，

2. $u,v$ 不连通，且连起来的两个连通块要么是树，要么是基环树，且不都是基环树。

我们发现第二类贡献的形式非常麻烦，首先这个基环树的限制不好处理，其次我们还要讨论三种情况。

正难则反，我们考虑这条边不会产生贡献的情况。

那就是：

1. $u,v$ 连通，且该连通块不是树。
2. $u,v$ 不连通，且连起来的两个连通块都不是树。

对于第一类贡献，考虑算出 $f[S]$ 表示点集 $S$ 的导出子图的生成树个数，这可以通过枚举子集做到 $\Theta(3^n)$。

具体地，枚举最后加入的一条边所连接起的两个连通块 $T$ 和 $S-T$，然后在连接这两个连通块的边中任选一条作为“最后加入的一条边” 即可。

为了避免重复的枚举，我们选出一个特殊点 $pos$，钦定 $T$ 包含这个点。（在很多图计数中，会看到“枚举 $1$ 号点所在的连通块”，其实就是这个意思，避免算重）

（注意：类加完答案之后要除以 $|S| - 1$，因为同一棵树会被这种方法算这么多次）

如何快速求出两个连通块之间连了多少条边？预处理 $cnt[S]$ 表示点集 $S$ 的导出子图有多少条边，那么边数就是 $cnt[S] - cnt[T] - cnt[S - T]$。

我们还要算出 $g[S]$ 表示点集 $S$ 的导出子图的连通子图的个数，这个也可以用一个容斥做到 $\Theta(3^n)$，即枚举特殊点 $pos$ 所在的连通块点集。

那么第一类贡献就很好计算了，直接枚举 $u,v$ 所在的连通块即可。

第二类贡献也很好计算，我们枚举 $u,v$ 分别属于哪两个连通块，设为 $A,B$，那因为一个连通块 $S$ 不是树的方案数就是 $g[S] - f[S]$，贡献系数就是 $(g[A] - f[A])(g[B] - f[B])$，因为在 $A\cup B$ 外的边可以任意排布，我们还需乘上 $cnt[U - A - B]$，其中 $U$ 为全集。

注意到上面算的一直都是方案数，我们除以总数将其转为概率，再用总概率 $\dfrac{1}{2}$ 去减即可（$\dfrac{1}{2}$ 是因为当前考虑的这条边必须选）。

总时间复杂度为 $\Theta(m 3^n)$，略微卡常，需要一些剪枝。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 17,Sz = 1 << 15,M = 65,P = 998244353;
inline int Add(int a,int b) { return (a + b >= P) ? (a + b - P) : (a + b);}
inline int Sub(int a,int b) { return (a < b) ? (a - b + P) : (a - b);}
inline int qpow(int a,int b) { int res = 1;while(b) {if(b&1) res = 1ll * res * a % P;a = 1ll * a * a % P;b >>= 1;} return res;}
struct Edge{
	int u,v,w;
	Edge(){}
	Edge(const int _u,const int _v,const int _w):
		u(_u),v(_v),w(_w){}
	bool operator < (const Edge &rhs) const { return w > rhs.w;}
};
int n,m;
Edge e[M];
int f[Sz],g[Sz];
int pop[Sz];
int cnt[Sz]; // 每个点集的导出子图的边数
int Pow2[M];
int inv[N];
int Solve(int x) // 当前扫到第 x 条边
{
	memset(cnt,0,sizeof cnt);
	for(int i = 1;i < x;i++)
		++cnt[(1 << e[i].u) | (1 << e[i].v)];
	for(int j = 0;j < n;j++)
		for(int i = 0;i < (1 << n);i++)
			if((i >> j) & 1)
				cnt[i] += cnt[i ^ (1 << j)];
	f[0] = g[0] = 0;
	int all = (1 << n) - 1;
	for(int S = 1;S <= all;++S)
	{
		if(pop[S] == 1) {f[S] = g[S] = 1;continue;}
		if(cnt[S] < pop[S] - 1) { f[S] = g[S] = 0;continue;}
		f[S] = 0;g[S] = Pow2[cnt[S]];
		int z = S & (-S),w = S ^ z;
		for(int T = w;T;T = (T - 1) & w)
		{
			int bu = S ^ T,num = cnt[S] - cnt[T] - cnt[bu]; // bu 中包含了特殊点 z
			f[S] = Add(f[S], 1ll * f[T] * f[bu] % P * num % P);
			g[S] = Sub(g[S],1ll * g[bu] * Pow2[cnt[T]] % P);
		}
		f[S] = 1ll * f[S] * inv[pop[S] - 1] % P;
	}
	for(int S = 1;S <= all;++S)
		g[S] = Sub(g[S],f[S]);
	int res = 0;
	int u = 1 << e[x].u,v = 1 << e[x].v;
	for(int S = 1;S <= all;++S)
	{
		if(!(S & u) || !(S & v)) continue;
		res = Add(res,1ll * g[S] * Pow2[cnt[all ^ S]] % P);
	}
	// 第二类贡献
	for(int A = 1;A <= all;++A)
	{
		if((A & v) || !(A & u)) continue;
		int buA = all ^ A;
		for(int B = buA;B;B = (B - 1) & buA)
		{
			if(!(B & v)) continue;
			res = Add(res,1ll * g[A] * g[B] % P * Pow2[cnt[all ^ A ^ B]] % P);
		}
	}
	int allp = (P + 1) / 2;
	res = 1ll * res * qpow(Pow2[x],P - 2) % P;
	res = Sub(allp,res);
	res = 1ll * res * e[x].w % P;
	return res;
}
int main()
{
	cin >> n >> m;
	for(int i = 1;i <= m;i++)
	{
		cin >> e[i].u >> e[i].v >> e[i].w;
		--e[i].u;--e[i].v;
	}
	sort(e + 1,e + m + 1);

	for(int i = 1;i < (1 << n);i++) pop[i] = pop[i >> 1] + (i & 1);
	Pow2[0] = 1;
	for(int i = 1;i <= m;i++) Pow2[i] = 2ll * Pow2[i - 1] % P;
	inv[1] = 1;
	for(int i = 2;i <= n;i++) inv[i] = 1ll * inv[P % i] * (P - P / i) % P;
	int ans = 0;
	for(int i = 1;i <= m;i++)
		ans = Add(ans,Solve(i));
	cout << ans << endl;
	return 0;
}
```

转化题意还是很妙的，但后半部分不知道如何评价。
<!--more-->

看到题之后，一眼会有一个直接考虑四种方向，直接 DP 的思路，显然做不得。

问题主要在于没法将两维独立开来。

这说明直接考虑 $(x,y)$ 行不通，我们得考察一些性质更好的量。

考察 $(x + y,x - y)$（即将坐标轴 45 度旋转，我也不知道出题人是怎么想到的）

如果 $x \gets x + D$，那么 $x + y$ 和 $x - y$ 都会加上 $D$。

如果 $x \gets x -D$，那么 $x + y$ 和 $x - y$ 都会减去 $D$。

如果 $y \gets y + D$，那么 $x + y$ 会加 $D$，$x - y$ 会减 $D$。

如果 $y \gets y - D$，那么 $x + y$ 会减 $D$，$x - y$ 会加 $D$。

容易发现，此时 $x + y$ 要么 $+D$，要么 $-D$，且 $x + y$ 的决策和 $x - y$ 无关。

用 bitset 优化 01 背包，看看 $x + y$ 和 $x - y$ 是否均能被表出即可。

为了避免在背包时出现负数，我们先默认每个 $d_i$ 都取减号，取加号时，认为其带来 $2d_i$ 的贡献。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 2e3 + 5,S = 3.6e6 + 5;
bitset<S> f[N];
int n,d[N],sumd;
int x,y;
int ans[N];
int main()
{
	cin >> n >> x >> y;
	for(int i = 1;i <= n;i++) cin >> d[i],sumd += d[i];
	int a = x + y,b = x - y;
	if(abs(a) > sumd || abs(b) > sumd) return puts("No"),0;
	if((a + sumd) & 1) return puts("No"),0;
	if((b + sumd) & 1) return puts("No"),0;
	a = (a + sumd) / 2;b = (b + sumd) / 2;
	f[0][0] = 1;
	for(int i = 1;i <= n;i++)
		f[i] = f[i - 1] | (f[i - 1] << d[i]);
	if(!f[n][a] || !f[n][b]) return puts("No"),0;
	puts("Yes");
	for(int i = n;i >= 1;i--)
	{
		if(!f[i - 1][a]) {ans[i] += 1;a -= d[i];}
		if(!f[i - 1][b]) {ans[i] += 2;b -= d[i];}
	}
	for(int i = 1;i <= n;i++)
	{
		// 默认是 -，那一位有值就是 +
		if(ans[i] == 0) putchar('L');
		if(ans[i] == 1) putchar('U');
		if(ans[i] == 2) putchar('D');
		if(ans[i] == 3) putchar('R');
	}
	return 0;
	return 0;
}
```

这题还是想岔了一些，也有可能是图画错了，有些性质观察得并不是很彻底。和题解无限接近了属于是（

<!--more-->

对于一个区间 $[l,r]$ ，显然，对于初始数 $t$，设 $f(t)$ 表示最终值那么 $f(t)$ 是一个关于 $t$ 的分段函数，且最多 $r - l + 2$ 段，因为只会减 $0 \sim (r - l + 1)$ 个 $p$。

对于一段数列，设 $c_x$ 表示初始数最少是多少，使得做完这个数列之后减去了 $x$ 个 $p$。

在序列上的问题， $n$ 又高达 $10^6$，当然首选线段树。

考虑怎么合并 $[l,mid]$ 和 $(mid,r]$ 的 $c$ 数组。

当然是用左边的 $c_x$ 和右边的 $c_y$ 来更新 $c_{x+y}$。

下文设 $[l,mid]$ 的和为 $Sl$。

考虑更新的条件，我们要确保对于一个在 $[c_x,c_{x+1})$ 中的数，其在做完左边之后还大于等于 $c_y$。

那么就有条件 $c_{x +1} - 1 + Sl - xp \ge c_y$。

那么更新的时候，从 $mid$ 反推回 $l$，就得到转移式 $c_{x+y} \gets \min\{c_{x+y},\max\{c_x,c_y + xp - Sl\}\}$。 

直接这么做的话，合并两个区间的复杂度是平方的，不如暴力。

事实上，对于这种  $h_{x+y} \gets \min\{h_{x+y},\max\{f_x,g_y\}\}$ 的转移，是可以考虑双指针优化的。（当然，要求 $f,g,h$ 均单调）

考察双指针的可行性，首先，$c$ 肯定是单调递增的。

我们再说明，对于 $x + y$ 相同的转移，我们取 $x$ 最小的一定不劣。

即证明 $(x,y)$ 不劣于 $(x+1,y-1)$。

首先有 $c_{x+1} - 1 + Sl - xp \ge c_{y}$，即 $c_{y} - Sl + xp < c_{x+1}$。

且有 $c_x < c_{x+1}$。

所以 $\max\{c_x,c_y + xp - Sl\} < c_{x+1}$。

显然会有 $\max\{c_x,c_y + xp - Sl\} < \max\{c_{x+1},c_{y-1} + (x+1)p - Sl\}$。

但有这点还是不够，为了能够用指针维护决策点，我们还需说明，$c_{x+1} - 1 + Sl - xp$ 是关于 $x$ 单调递增的，也就是 $c_{x+1} - c_x \ge p$。

由于 $c_x$ 表示最小的初始值，所以 $c_x$ 经过一段区间后，最大值必定是 $0$，否则我们可以将初始值调小一点，所以我们需要再增加至少 $p$ 才可以再减掉一个 $p$。

那么，我们只需维护一个指针 $pos$，表示当前最大的满足条件的 $y$，在 $x$ 自增时，$pos$ 对应移动，用走到的那些 $y$ 转移即可。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 1e6 + 5,Sz = N << 2;
typedef long long ll;
const ll INF = 0x3f3f3f3f3f3f3f3f;
template<typename T> inline void ckmin(T &x,const T &y) { if(x > y) x = y;}
template<typename T> inline void ckmax(T &x,const T &y) { if(x < y) x = y;}
int n,m,p,a[N];

struct node{
	int l,r,len;
	ll sum;
	vector<ll> c;
};
node tr[Sz];
#define ls k << 1
#define rs k << 1 | 1
inline void pushup(int k)
{
	tr[k].sum = tr[ls].sum + tr[rs].sum;
	for(int x = 0,y = 0;x <= tr[ls].len;x++)
	{
		if(y > tr[rs].len) --y;
		for(;y <= tr[rs].len;++y)
		{
			ll val = tr[rs].c[y] + 1ll * x * p - tr[ls].sum;
			ll lim = tr[ls].c[x + 1] - 1 - 1ll * x * p + tr[ls].sum;
			if(lim < tr[rs].c[y]) {if(y) --y;break; /* 当前 y 不合法，要回退一个*/}
			ckmin(tr[k].c[x + y],max(tr[ls].c[x],val));
		}
	}
}
void build(int k,int l,int r)
{
	tr[k].l = l;tr[k].r = r;
	tr[k].len = r - l + 1;
	for(int i = 1;i <= tr[k].len + 2;i++) tr[k].c.push_back(INF);
	tr[k].c[0] = -INF;
	if(l == r) { tr[k].sum = a[l];tr[k].c[1] = p - a[l];return;}
	int mid = l + r >> 1;
	build(k << 1,l,mid);
	build(k << 1 | 1,mid + 1,r);
	pushup(k);
	// printf("[%d,%d]: ",l,r);
	// for(auto i : tr[k].c) printf("%d ",i);
	// printf("\n");
}
ll Now; // 全局变量，初始时为 0,遇到一个区间，就让 now = f(l,r,now)，最后拼凑出询问区间的答案。
void Query(int k,int l,int r,int x,int y)
{
	if(l > y || r < x) return;
	if(x <= l && r <= y) 
	{
		int pos = upper_bound(tr[k].c.begin(),tr[k].c.end(),Now) - tr[k].c.begin() - 1;
		Now = Now - 1ll * pos * p + tr[k].sum;
		return;
	}
	int mid = l + r >> 1;
	Query(k << 1,l,mid,x,y);
	Query(k << 1 | 1,mid + 1,r,x,y);
}
int main()
{
	ios::sync_with_stdio(false);
	cin.tie(0);cout.tie(0);
	cin >> n >> m >> p;
	for(int i = 1;i <= n;i++)
		cin >> a[i];
	build(1,1,n);
	for(int i = 1;i <= m;i++)
	{
		int l,r;
		cin >> l >> r;
		Now = 0;
		Query(1,1,n,l,r);
		cout << Now << endl;
	}
	return 0;
}
```

Backward Induction ，译为逆向归纳法，常用于在有向图上做带环的 DP 与博弈，是一个很有用的技巧。
<!--more-->

这种方法常用于，你要对每个点维护一个状态 $f_x$，而 $f_x$ 由后继 $f_y$ 推得的时候。

直接考虑环并不好做，我们先从简单的情况开始归纳，即 $x$ 没有出边的情况，这一般很简单。

然后对反图做类似拓扑排序 / dijkstra 的 DP，让 $y$ 一步一步更新 $x$，在队列/堆中存储已经确定的 $f_x$。



### 有向图博弈

有向图博弈，有环，那么就肯定存在平局。

要让博弈进行下去，肯定是有一方希望平局，另一方不希望平局。

先 DP 出每个状态是否为平局，再导出每个点的胜负状态即可。

DP 平局较为容易，没有出边肯定不是平局，对于希望平局的一方，后继有平则平，对于不希望平局的一方，后继有不平则不平，记录每个点在原图上的出度 $out[x]$，在原图上做拓扑排序式的 DP 即可。

怎么导出胜负状态呢？

我们一般会记录 $D[x][0/1]$，表示 $x$ 为起点，$A/B$ 先手，能到达多少个非平局后继。这样我们就可以在 DP 过程中判别， $x$ 的非平局后继是否都已经被确定。

如果 $x$ 的非平局后继都已经被确定，将其加入队列 / 堆等数据结构，更新其它点即可。

#### 第一道例题
[洛谷 P6970](https://www.luogu.com.cn/problem/P6970)

Alice : 先平再赢后输

Bob : 先赢再输后平

我们先 DP 出 $drw[x][0/1]$ 表示以 $x$ 为起点，$A/B$ 先手，是否为平局。

讲一下 DP 过程中的细节：

我们一开始将无出度节点的 $drw$ 置为 $0$，其余点的 $drw$ 均置为 $1$。

维护一个队列 $Q$，里面只会存放非平局的状态。

取出队头 $(x,v \in \{0,1\})$，取出 $x$ 的前驱 $y$。

如果 $v = 0$，那么对应的，$y$ 那里是 Bob 先手，既然 Bob 不喜欢平局，$drw[y][1]$ 肯定为 $False$，更新并入队即可。

如果 $v = 1$，那么对应的，$y$ 那里是 Alice 先手，那得 $y$ 的所有后继均为非平局，$drw[y][0]$ 才是非平局，所以碰到 $(x,1)$，就把 $out[y] \gets out[y] - 1$，什么时候减到 $0$ 了，就更新并入队。

```cpp
for(int i = 1;i <= n;i++)
{
	deg[i] = out[i];
	if(!deg[i]) Q.emplace(i,0),Q.emplace(i,1);
	else drw[i][0] = drw[i][1] = 1;
}
while(!Q.empty())
{
	int x = Q.front().FI,tp = Q.front().SE; // 队列里只放非平局状态
	Q.pop();
	for(auto y : Gr[x])
        if((tp == 0 && drw[y][1]) || (tp == 1 && !--deg[y]))
	 		drw[y][tp ^ 1] = 0,Q.emplace(y,tp ^ 1);
}
```

然后对非平局状态 DP 出胜负即可，这个比较容易。

这题还有一个特殊情况，就是对于一些非平局状态，其在上一轮的 DP 中并没有确定胜负态。

对于 Bob 来说，这体现为该点在某个环上，后继有 Alice 的必胜与平局，在所有已经确定的状态都转移完之后，这些状态没有被转移到（因为在环上有相邻的点是非平局，导致无法进入这个环，因为相邻点的状态始终无法确定）。

那么这些点在环上，但为什么不是平局呢？

只有可能是 Bob 没法赢，但由不想平局，所以选择了输，特判这些点为 Alice 胜 Bob 败即可。

```cpp
for(int i = 1;i <= n;i++)
	{
		deg[i] = out[i];
		if(!deg[i]) Q.emplace(i,0),Q.emplace(i,1);
		else F[i][0] = F[i][1] = -1;
		for(auto v : G[i])
			D[i][0] += !drw[v][1],D[i][1] += !drw[v][0];
	}
	while(!Q.empty())
	{
		int x = Q.front().FI,tp = Q.front().SE;Q.pop(); // 做出非平局状态的输赢
		for(auto y : Gr[x]) 
			if(!drw[y][tp ^ 1]) // 目标状态非平局
			{
				if(F[x][tp]) { if(!--D[y][tp ^ 1]) Q.emplace(y,tp ^ 1),F[y][tp ^ 1] = 0;}
				else {if(F[y][tp ^ 1] == -1) Q.emplace(y,tp ^ 1),F[y][tp ^ 1] = 1;}
			} 
	}
	for(int i = 1;i <= n;i++) // 特判上述情况
	{
		if(F[i][0] == -1) F[i][0] = 1;
		if(F[i][1] == -1) F[i][1] = 0;
	}
```

### 有向图 DP

与有向图博弈的流程大同小异，先考虑没有出度的点，再使用类似 Dijkstra 的方式维护转移即可。



#### 第一道例题

[AtCoder Beginning Contest 261 H](https://www.luogu.com.cn/problem/AT_abc261_h)

这道题是个博弈与 DP 结合的题，放在这里比较合适。

容易发现，Aoki 当然会尽量促成 "INFINITY"。

设 $F[x][0/1]$ 表示以 $x$ 为起点，Takahashi/Aoki 先手的最终得分，初始时 $F[x][0] = \infty,F[x][1] = 0$。

对于没有出度的点，$F[x][0] = F[x][1] = 0$，将其加入堆。

有转移：
$$
\begin{cases}
f_{x,0} \gets \min_{(x,y,w) \in E}f_{y,1} + w \\
f_{x,1} \gets \max_{(x,y,w) \in E}f_{y,0} + w \\
\end{cases}
$$
事实上，我们可以直接把平局的情况并入上述的转移。

如果有一个 $f_{y,1}$ 有值，那么 $f_{x,0}$ 就肯定有值。

如果所有的 $f_{y,0}$ 有值，那么 $f_{x,1}$ 才会有值。

上述的有值就是不为 $\infty$ 的情况。

以上述规则转移即可。

在这里，我们维护可用状态用的是小根堆，这与 dijkstra 是本质相同的，我们只会从小的 DP 值转移到大的 DP 值，什么时候一个状态从堆中被弹出了，那它就已经确定了，因为比它小的 DP 值已经都被弹出，所有能更新它的转移都已经做完了。

如果还使用队列的话，那么这就与 SPFA 本质相同，你就无法在每个状态第一次出队时确定它，而是需要若干次松弛，直到状态收敛，这样就无法保证复杂度了。

```cpp
#include <bits/stdc++.h>
#define FI first
#define SE second
using namespace std;
typedef long long ll;
const int N = 2e5 + 5;
int n,m,s;
vector<pair<int,int> > G[N],Gr[N];
ll f[N][2];
int out[N][2];
struct node{
	int x,tp;
	ll val;
	node(){}
	node(const int _x,const int _tp,const ll _val):
		x(_x),tp(_tp),val(_val){}
	bool operator < (const node &rhs) const { return val > rhs.val;}
};
priority_queue<node> Q;
int deg[N][2];
int vst[N][2];
inline void Dijk()
{
	while(!Q.empty())
	{
		int x = Q.top().x,tp = Q.top().tp;
		// if(Q.top().val != f[x][tp]) { Q.pop();continue;}
		Q.pop();
		if(vst[x][tp]) continue;
		vst[x][tp] = true;
		for(auto it : Gr[x])
		{
			int y = it.FI,w = it.SE;
			if(tp == 0) f[y][1] = max(f[y][1],f[x][0] + w);
			if(tp == 1) f[y][0] = min(f[y][0],f[x][1] + w);
			deg[y][tp ^ 1]--;
			if(!deg[y][tp ^ 1]) Q.push(node(y,tp ^ 1,f[y][tp ^ 1]));
			else if(tp == 1) Q.push(node(y,0,f[y][0])); // 对于先手而言，只要一个转移边有值就可以更新
		}
	}
}
int main()
{
	cin >> n >> m >> s;
	for(int i = 1;i <= m;i++)
	{
		int a,b,c;
		cin >> a >> b >> c;
		Gr[b].emplace_back(a,c);
		++deg[a][0];++deg[a][1];
	}
	for(int i = 1;i <= n;i++)
		f[i][0] = 9e18;
	for(int i = 1;i <= n;i++)
		if(!deg[i][0])
		{
			Q.push(node(i,0,f[i][0] = 0));
			Q.push(node(i,1,f[i][1] = 0));
		}
	Dijk();
	if(!vst[s][0]) puts("INFINITY");
	else cout << f[s][0] << endl;
	return 0;
}
```

当然，也是可以先按照上文的方法 DP 出每个状态是否平局，然后用优先队列转移非平局状态。

#### 第二道例题

[洛谷 P4042](https://www.luogu.com.cn/problem/P4042)

这题，令 $dp_i$ 表示消灭 $i$ 号怪兽的最小代价，那么有 
$$
dp_i = \min(K_i,S_i + \sum_{(i,j) \in E} dp_j)
$$
因为这题每个状态都最终会有个确定的值，并不需要像上一题一样加入特殊的转移规则，转移比较普通。

也是因此，我们可以等到每个点的后继均被确定，再将其入队，事实上，这样每个点只会被入队一次。

因为不确定要让哪些点的 DP 值取到 $K_i$，我们一开始将所有 $(i,K_i)$ 入队即可。

每个点算上最开始的一次入堆，最多被入堆两次，时间复杂度为 $\Theta(n \log n + m)$。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 2e5 + 5,M = 1e6 + 5;
typedef long long ll;
int n,R[N];
ll S[N],K[N];
vector<int> G[N];
ll dp[N];
struct node{
	int id;ll val;
	node(){}
	node(const int _id,const ll _val):id(_id),val(_val){}
	bool operator < (const node &rhs) const { return val > rhs.val;}
};
priority_queue<node> Q;
int vst[N];
ll ans[N];
int main()
{
	cin >> n;
	for(int i = 1;i <= n;i++)
	{
		cin >> S[i] >> K[i];
		int k;
		cin >> k;R[i] = k;
		for(int j = 1,x;j <= k;j++)
			cin >> x,G[x].push_back(i);
	}
	for(int i = 1;i <= n;i++)
	{
		dp[i] = S[i]; // 维护 S[i] + \sum dp_j
		Q.push(node(i,K[i]));
	}
	while(!Q.empty())
	{
		int x = Q.top().id;
		ll val = Q.top().val;
		Q.pop();
		if(vst[x]) continue;
		vst[x] = true;ans[x] = val;
		for(auto y : G[x])
		{
			if(vst[y] || dp[y] > K[y]) continue;
			R[y]--;dp[y] += val;
			if(!R[y]) Q.push(node(y,dp[y]));
		}
	}
	cout << ans[1] << endl;
	return 0;
}
```

这种在有向图上的 DP 有一个共性：由小的 DP 值转移到大的 DP 值，所以用小根堆维护当前可用的状态即可。

这与 dijkstra 的正确性是本质相同的，事实上，最短路问题也可以看作在有环图上的最优化 DP。

#### 第三道例题

[[CCO2021] Travelling Merchant](https://www.luogu.com.cn/problem/P7831)

设 $f_x$ 表示从 $x$ 出发，至少需要多少资产可以一直走下去，可以写一个转移： $f_x \gets \min_{(x,y,r,p) \in E}\max(r,f_y - p)$。

还是考虑没有出度的点，显然  $f_x$ 为 $\infty$，答案为 $-1$。

如果不断删去出度为 $0$ 的点，最后剩下的点一定是有答案的（即在环上的点）

读者从前面的题可以发现，对于这种有环的 DP,我们可以考察答案的界，来看看答案会收敛成什么样子。

我们考虑这些点的答案上界。

显然，取出当前最大的 $r$，那么如果你初始有 $r$ 的资产，那就可以通行全图，因为资产不会减少。

取出这条边的起点 $u$，并将 $f_u$ 对 $r$ 取 $\min$，再删掉这条边。

如果删完之后这条边已经没有出边了，说明 $f_x$ 已经确定，可以拿来更新其它的点，将其放入一个队列。

跑类似上文的 DP 即可，一边松弛答案，一边观察目标点的后继是否全被删空，要注意，给每条边打个标记，使得每条边只被删一次。

在寻常的 Backward DP 中，打标记并不是必要的，一来每个状态入队不一定只有一次（比如上一道题），二来不打标记也只会对常数造成影响。

但是这道题中，我们要一边找当前 $r$ 最大的边，一边去做 Backward DP 来更新 $f$ 数组，为了让这两个过程不重复统计，我们对每条边打了个删除标记。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 2e5 + 5;
int n,m;
struct Edge{
	int a,b,r,p;
	Edge(){}
	Edge(const int _a,const int _b,const int _r,const int _p):
		a(_a),b(_b),r(_r),p(_p){}
	bool operator < (const Edge &rhs) const { return r > rhs.r;}
};
Edge p[N];
vector<int> G[N];
queue<int> Q;
bool vst[N];
int out[N];
int ans[N];
int main()
{
	cin >> n >> m;
	for(int i = 1;i <= m;i++)
		cin >> p[i].a >> p[i].b >> p[i].r >> p[i].p;
	sort(p + 1,p + m + 1);
	for(int i = 1;i <= m;i++)
		G[p[i].b].push_back(i);
	for(int i = 1;i <= m;i++)
		++out[p[i].a];
	for(int i = 1;i <= n;i++)
		ans[i] = 2e9;
	for(int i = 1;i <= n;i++)
		if(!out[i]) Q.push(i);
	for(int i = 1;i <= m;i++)
	{
		while(!Q.empty())
		{
			int x = Q.front();Q.pop();
			for(auto id : G[x])
			{
				if(vst[id]) continue;
				int y = p[id].a;
				vst[id] = true;
				--out[y];
				if(ans[x] < 2e9) ans[y] = min(ans[y],max(p[id].r,ans[x] - p[id].p));
				if(!out[y])	
					Q.push(y);

			}
		}
		if(vst[i]) continue;
		ans[p[i].a] = min(ans[p[i].a],p[i].r);
		vst[i] = true;
		--out[p[i].a];
		if(!out[p[i].a]) Q.push(p[i].a);
	}
	for(int i = 1;i <= n;i++)
		if(ans[i] >= 2e9) printf("-1 ");
		else printf("%d ",ans[i]);
	printf("\n");
	return 0;
}
```

比起题解区的神奇构造，我更喜欢@约瑟夫用脑玩 的思维模式，能够推广到更加普适的问题，为图论解题提供启发，我们接下来讲述一下这种做法。

<!--more-->

考虑到这是个 DAG，我们不妨对每个点设一个深度 $dp_x$，然后强制在删完后的图中，边 $(x,y)$ 等价于 $dp_y = dp_x + 1$，那么原限制等价于，不存在 $dp_x \ge 3$  的点。

考察特殊对象是 OI 中的常见手段，我们在这道题中，首先考察入度为 $0$ 的点，那么其深度为 $1$。

深度为 $1$ 的点指出去的点，要么深度为 $2$，要么就被删掉。

而深度为 $2$ 的点指出去的点，一定要被删掉。

因为我们要删掉的尽量少，一个点肯定不能随便成为深度为 $2$ 的点。

如果一个点，比它拓扑序小的都确定了，且有深度为 $1$ 的点指向它，那么它就只能是深度为 $2$ 的点。

因为深度为 $3$ 的点等价于被删掉，所以，如果一个点的入边都是深度为 $3$ 的点，它和深度为 $1$ 的点是等效的。

按照上面的规则，按拓扑序更新 $dp_x$ 即可。

设 $dp_x = i$ 的点的个数为 $C_i$。

因为出度 $\le 2$，所以 $C_2 \le 2C_1 ,C_0 \le 2C_2$

容易发现 $C_0 \le \dfrac{4n}{7}$。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 2e5 + 5;
int n,m;
vector<int> G[N];
int dep[N],deg[N];
queue<int> Q;
inline void Work()
{
	cin >> n >> m;
	for(int i = 1;i <= n;i++) dep[i] = deg[i] = 0,G[i].clear();
	for(int i = 1;i <= m;i++)
	{
		int x,y;
		cin >> x >> y;
		G[x].push_back(y);++deg[y];
	}
	for(int i = 1;i <= n;i++)
		if(!deg[i]) Q.push(i),dep[i] = 1;
	//	else dep[i] = 1e9;
	while(!Q.empty()) // dp = -1 表示已经被删除;dp = 0 表示所有入边都是被删的点，我们在入队时会把这种情况置为 1
	{
		int x = Q.front();Q.pop();
		// printf("dep[%d]=%d\n",x,dep[x]);
		for(auto y : G[x])
		{
			--deg[y];
			if(dep[x] != -1)
			{
				if(dep[x] == 1 && dep[y] != -1) dep[y] = 2;
				else dep[y] = -1;
			}
			if(!deg[y]) {Q.push(y); if(dep[y] == 0) dep[y] = 1;}
		}
	}
	vector<int> Ans;
	for(int i = 1;i <= n;i++)
		if(dep[i] == -1) Ans.push_back(i);
	printf("%lu\n",Ans.size());
	for(auto i : Ans) printf("%d ",i);
	printf("\n");
}
int main()
{
	int T;
	cin >> T;
	while(T--) Work();
	return 0;
}
```

这是道充分体现了水淹笛卡尔树这个模型的应用的好题。

类似题目：洛谷 P5999，ARC117E

<!--more-->

观察这题的权值函数，与排列的相邻元素有关，与元素的大小关系有关。

而笛卡尔树，它的中序遍历记录了位置相关信息，它的拓扑序记录了权值相关信息。

而水淹笛卡尔树，就是一类在笛卡尔树上按层/权值 DP 的思路。

往往我们并不需要显式地说明笛卡尔树的构型，也有些时候，这类题目可以不用笛卡尔树来理解。

既然是按权值 DP ，我们考虑从小到大插入每个数 $i$。

在 $i$ 之前，已经插入的数会形成若干个连续段，这些数的贡献是已经计算了的，我们只需知道 $i$ 与两侧数的大小关系，即可计算 $i$ 的贡献。

在写方程之前，重写一下题目所给的量：$a_i \gets a_i + x_i,b_i \gets b_i - x_i,c_i \gets c_i + x_i,d_i \gets d_i - x_i$。

那么 $$f(i,j) = \begin{cases} c_i + b_j ,i > j \\ d_i + a_j,i < j \\ \end{cases}$$

考察 $i$ 的转移：

先考虑 $i \ne s,t$ 的情况：

1. $i$ 把已有的两段接起来，在 $j > 1$ 时转移，显然 $i$ 两侧的数小于 $i$，那么 $i$ 的贡献就是 $a_i + c_i$，则有转移 $f_{i,j-1} \gets f_{i-1,j} + a_i + c_i$。

2. $i$ 新开一段，那么它周围的两个数都大于它，在 $j = 1$ 且 $i > s,t$ 时无法转移：

   $f_{i,j+1} \gets f_{i-1,j} + b_i + d_i$。

3. $i$ 接在某一段的左边，在 $j = 1$ 且 $i > s$ 时无法转移：

   $f_{i,j} \gets f_{i-1,j} + c_i + b_i$。

4. $i$ 接在某一段的右边，在 $j = 1$ 且 $i > e$ 时无法转移：

   $f_{i,j} \gets f_{i-1,j} + a_i + d_i$。

在 $i = s$ 或 $i = t$ 时，新开一段或接在某一段边上即可。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 5e3 + 5;
typedef long long ll;
template<typename T> inline void ckmin(T &x,const T &y) { if(x > y) x = y;}
ll f[2][N];
int n,s,t;
int X[N],a[N],b[N],c[N],d[N];
int main()
{
	cin >> n >> s >> t;
	for(int i = 1;i <= n;i++) cin >> X[i];
	for(int i = 1;i <= n;i++) cin >> a[i],a[i] += X[i];
	for(int i = 1;i <= n;i++) cin >> b[i],b[i] -= X[i];
	for(int i = 1;i <= n;i++) cin >> c[i],c[i] += X[i];
	for(int i = 1;i <= n;i++) cin >> d[i],d[i] -= X[i];
	memset(f,0x3f,sizeof f);
	f[0][0] = 0;
	for(int i = 1;i <= n;i++)
	{
		memset(f[i&1],0x3f,sizeof f[i&1]);
		if(i != s && i != t)
			for(int j = 0;j < i;j++)
			{
				ll val = f[(i-1)&1][j];
				if((i < max(s,t)) || j > 1) ckmin(f[i&1][j + 1],val + b[i] + d[i]); // 新开一段
				if(j > 1) ckmin(f[i&1][j - 1],val + a[i] + c[i]);
				if(j > 0 && (j > 1 || i < s)) ckmin(f[i&1][j],val + c[i] + b[i]);
				if(j > 0 && (j > 1 || i < t)) ckmin(f[i&1][j],val + a[i] + d[i]);
			}
		if(i == s)
			for(int j = 0;j < i;j++)
			{
				ll val = f[(i-1)&1][j];
				// 新开一段或贴在左边
				ckmin(f[i&1][j+1],val + d[i]);
				if(j > 0) ckmin(f[i&1][j],val + c[i]);
			}
		if(i == t)
			for(int j = 0;j < i;j++)
			{
				ll val = f[(i-1)&1][j];
				ckmin(f[i&1][j+1],val + b[i]);
				if(j > 0) ckmin(f[i&1][j],val + a[i]);
			}
	}
	cout << f[n&1][1] << endl;
	return 0;
}
```

本题我是想到了个做法的，成功的过了第一个样例，后来与题解比对，发现我的做法考察的条件还是太弱了（
<!--more-->

容易发现，最后的每个字符都是由原串的一段区间操作得来的。

把 A,B,C 的权值分别看成 $1,2,3$，那么一次操作相当于替换为异或和。

考虑选出一段区间能干嘛：

1. 如果这段区间的异或和为 $0$，显然不能操作为单个字符。
2. 如果这段区间只有一种字符，显然啥都干不了。
3. 除开上述两种情况，归纳可得这段区间肯定能被操作成单个字符。我们称这类区间为 “好段”

（我之前的做法默认区间长度 $\le 4$，理所当然的寄了）

然后就是利用常规的思维模式，考虑如何让原串 $S$ 唯一映射到能被构造出来的串 $T$。

首先 $T$ 的异或和要等于 $S$ 的异或和。

其次，我们在找方案的时候，只考虑每个“好段”右端点最靠前的方案。

有一个转移方法是，每次选一个最短的可行的段向后转移，如果 $T$ 的最后一个字符取完了但还有剩余，就把剩下的字符全部补在后面（显然这些字符异或和肯定为 $0$）。

为了说明正确性，我们要说明对于可以被构造的串 $T$，上述方法一定能够构造一个方案。

我们取出串 $T$ 的任意一个方案，去掉第一个“好段”的最长的异或和 $0$ 的后缀，且保证去掉后第一段仍是“好段”，把这段后缀接在第二个”好段“的前方，以此类推，这样得到的方案就能被上面的转移方法所表示。

那么我们设 $dp[i]$ 表示处理了前 $i$ 个字符的方案数，预处理 $nxt[i][k]$ 表示 $i$ 位置往后最短的异或和为 $k$ 的“好段”，据此转移即可。

最后取出 $i + 1 \sim n$ 的异或和为 $0$ 的位置 $i$，将答案加上 $f[i]$ 即可。

注意整个串清一色要特判，这个时候补 $0$ 操作是错的，但答案为 $1$。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 1e6 + 5,P = 1e9 + 7;
int n;
char s[N];
int f[N];
int ton[4],nxt[N][4];
int sum[N];
int main()
{
	cin >> n >> (s + 1);
	int flg = 1;
	for(int i = 1;i <= n;i++)
	{
		if(i < n) flg &= (s[i] == s[i + 1]);
		sum[i] = sum[i - 1] ^ (s[i] == 'A' ? 1 : (s[i] == 'B' ? 2 : 3));
	}
	if(flg) return puts("1"),0;
	for(int i = 1;i <= 3;i++)
		ton[i] = n + 1;
	for(int i = n;i >= 0;i--)
	{
		ton[sum[i]] = i;
		for(int k = 0;k <= 3;k++)
			if(k != sum[i])
				nxt[i][sum[i] ^ k] = ton[k];
		nxt[i][sum[i] ^ sum[i + 1]] = i + 1;
	}
	f[0] = 1;
	for(int i = 0;i < n;i++)
		for(int k = 1;k <= 3;k++)
			(f[nxt[i][k]] += f[i]) %= P;
	int ans = 0;
	for(int i = 1;i <= n;i++)
		if(sum[i] == sum[n])
			(ans += f[i]) %= P;
	cout << ans << endl;
	return 0;
}
```

本题一开始读错题了，把题目加强了好多。（

本题有经典的**去叶子归纳法**，值得学习。

<!--more-->

考虑知道了标号之后怎么判断合法。

考虑一个叶子和其连向父亲的边。

如果边是 OR，点是 $1$，原问题一定有解。

如果边是 OR，点是 $0$，或者边是 AND，点是 $1$，那这个叶子对答案没有影响，可以直接舍弃。

如果边是 AND，点是 $0$，要尽量早的把这个叶子缩掉，这样对后面的危害最小。

把这个步骤由深往浅的归纳，就会发现，我们对一棵子树只需要记录两个信息：最终的权值，以及有没有一个连通块向外恰好连了一条 OR 边 且最终权值为 $1$ 。

说白了就是记录在整个过程中，有没有出现 "OR 1" 型的叶子。

设出状态 $f_{x,0/1/2}$ 表示 $x$ 子树的最终权值为 $0$ / 为 $1$ 且没有 "OR 1" 型叶子 / 有 "OR 1" 型叶子。

那么状态转移如下：
$$
\begin{aligned}
f'_{x,0} &\gets 2f_{x,0}f_{y,0} + f_{x,1}f_{y,0} + f_{x,0}f_{y,1} \\
f'_{x,1} &\gets f_{x,1}(f_{y,1} + f_{y,0}) \\
f'_{x,2} &\gets 2(f_{x,2}(f_{y,0} + f_{y,1} + f_{y,2}) + f_{y,2}(f_{x,0} + f_{x,1})) + f_{y,1}(f_{x,0} + f_{x,1}) \\
\end{aligned}
$$
第一行：$0$ and $0$，$0$ or $0$，$1$ and $0$，$0$ and $1$。

第二行： 因为没有 "OR 1" 型叶子，$y$ 子树必须是 "AND 1" 或者 "OR 0"，那么 $x$ 所属连通块权值必然为 $1$。

第三行：前面是任意一侧有 "OR 1" 型叶子的情况，后面是 $y$ 子树是 "OR 1" 型叶子的情况。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 1e5 + 5,P = 998244353;
inline int Add(int a,int b) { return (a + b >= P) ? (a + b - P) : (a + b);}
int n;
vector<int> G[N];
int f[N][3];
void dp(int x,int fa)
{
	f[x][0] = f[x][1] = 1;
	for(auto y : G[x])
	{
		if(y == fa) continue;
		dp(y,x);
		int v0 = f[x][0],v1 = f[x][1],v2 = f[x][2];
		f[x][2] = Add(2ll * v2 * Add(f[y][2],Add(f[y][0],f[y][1])) % P,Add(2ll * f[y][2] * (v0 + v1) % P,1ll * f[y][1] * (v0 + v1) % P));
		f[x][0] = Add(Add(2ll * v0 * f[y][0] % P , 1ll * v0 * f[y][1] % P),1ll * v1 * f[y][0] % P);
		f[x][1] = 1ll * v1 * (f[y][1] + f[y][0]) % P;
	}	
}
int main()
{
	cin >> n;
	for(int i = 1;i < n;i++)
	{
		int x,y;
		cin >> x >> y;
		G[x].push_back(y);
		G[y].push_back(x);
	}
	dp(1,0);
	cout << Add(f[1][1],f[1][2]) << endl;
	return 0;
}
```

这题让我没什么头绪。想到过使用前缀和来转换，但 $\pm 1$ 的变化量看上去非常难以处理。最后发现是一个从未见过的 DP 模型，果然 ARC 题还是有学习价值的（前提是找得到好题）。

<!--more-->

题意：计数满足下列条件的长度为 $2n$ 的序列 $a_1,a_2,\dots,a_{2n}$：

1. 恰好包含 $n$ 个 $+1$ 和 $n$ 个 $-1$。
2. 恰好有 $K$ 对 $(l,r) (1 \le l \le r \le n)$ 满足 $a_l + a_{l+1} + \dots + a_r = 0$

$1 \le n \le 30,1 \le K \le n^2$。

求出 $a$ 的前缀和 $S$，设 $O_i$ 表示有多少个 $S$ 等于 $i$，那么上述条件等价于：$S_0 = S_{2n} = 0,\sum_i \binom{O_i}{2} = K$。

另一方面，$S_i - S_{i + 1} = \pm 1$。

注意到这个 $K$ 的约束是关于每种值独立的，我们尝试设计关于值的 DP。

要把值的限制和相差 $\pm 1$ 的限制统一起来，我们尝试 DP 这个序列 S 的笛卡尔树。

如下图：

![](/images/ARC117E-1.png)

我们在这个笛卡尔树上，从上到下，一层一层的 DP,每次填完一层的所有数。

设 $dp_{i,j,k,c}$ 表示一共填了 $i$ 个数，已经填的数在 $S$ 序列上形成 $j$ 个连续段，一共填了 $k$ 层，当前的 $\sum \binom{O_i}{2} = c$ 的方案数。

 考虑最后怎么求答案，因为最后强制 $S_0 = S_{2n} = 0$，我们考虑把 $S \lt 0$ 和 $S \ge 0$ 的部分拼接起来。

注意到这两种情况是对称的，我们都可以用这个 DP 状态来表示。

设 $g_{i,j,c} = \sum_k dp_{i,j,k,c}$。

具体地，因为拼的时候肯定是一段 $S \ge 0$ 和一段 $S < 0$ 交错，那么我们枚举 $S \ge 0$ 的个数 $i$，段数 $j$，这一部分的 $\sum_i \binom{O_i}{2} = c$，那么最后的答案就是 
$$
\sum_{i,j,c} g_{i,j,c}g_{2n + 1 - i,j - 1,K - c}
$$
进一步地，我们发现 DP 中的 $k$ 是没用的，可以去掉。

我们考虑新一层加入了 $x$ 个数的影响。

会出现一下三种情况：

1. 某两段之间的间隙被连接，需要占用一个位置，并把两个段合并成一个
2. 某个段间隙没有被连接，因为 $S$ 的变化连续，必须在这个间隙的两段贴两个数来拓展
3. 加入一个新的“山谷”

重点在于考虑段数的变化。

当前有 $j$ 个连续段，就有 $j + 1$ 个空隙，每个空隙中都必须填数（因为我们是从上到下来填的数，每次填的是当前序列中的最小值，而我们限制了序列两端是 $0$，所以两端的空隙也必须填数；另一方面，因为 $S$ 的变化是连续的，所以中间的空隙不填数就不合法了）

由上面三种情况整合可得，在单一个中间空隙中填入了 $a$ 个数，会给总段数带来 $a - 2$ 的变化量。两端则是 $a - 1$。

整理式子可得新的连续段数为 $x - j$。

考虑转移系数，相当于在 $j +1$ 个盒子里放 $x$ 个球，每个盒子都不为空，插板可得系数为 $\binom{x - 1}{j}$

综上所述，有转移 $dp_{i + x,x - j,c + \binom{x}{2}} \gets \binom{x - 1}{j} dp_{i,j,c}$。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 65;
typedef long long ll;
int n,k;
ll C[N][N];
ll dp[N][N][N * N];
int main()
{
	cin >> n >> k;
	C[0][0] = 1;
	for(int i = 1;i <= n + 1;i++)
	{
		C[i][0] = C[i][i] = 1;
		for(int j = 1;j < i;j++)
			C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
	}
	for(int x = 0;x <= n + 1;x++)
		if(x * (x - 1) / 2 <= k)
			dp[x][x][x * (x - 1) / 2] = 1;
	for(int i = 1;i <= 2 * n + 1;i++)
		for(int c = 0;c <= k;c++)
			for(int j = 1;j <= min(n + 1,i);j++)
			{
				ll val = dp[i][j][c];
				if(val)
				{
					for(int x = j + 1;x <= n + 1;x++)
					{
						int nxt_c = c + x * (x - 1) / 2;
						if(i + x > 2 * n + 1 || nxt_c > k) continue;
						dp[i + x][x - j][nxt_c] += C[x - 1][j] * val;
					}
				}
			}
	ll ans = 0;
	for(int i = 0;i <= 2 * n + 1;i++)
		for(int j = 1;j <= n + 1;j++)
			for(int c = 0;c <= k;c++)
				ans += dp[i][j][c] * dp[2 * n + 1 - i][j - 1][k - c];
	cout << ans << endl;
	return 0;
}
```

这题，我和王队一共看了一个小时，王队一句话让我突然想到了状态和相关的转移，然后花了半天把它写完。事实上我们都想到了这题的大部分解法。

<!--more-->

如果排列确定了，很容易有个 $\Theta(n^2)$ 的 DP,设 $dp[i][j]$ 表示当前走到点 $(i,j)$ 的方案数，转移不再赘述。

现在排列不确定了，我们枚举排列去计数路径是十分困难的，那反过来考虑，考察一条路径能贡献多少个排列。

那现在假设路径确定了，我们要绕开这条路径来填充排列。

“所有点都不经过”是十分困难的，我们可以**钦定** 有 $t$ 个点被经过，容斥系数为 $(-1)^t$。

需要注意的是，对于已经确定的 $p_i$，其带来的限制是 "第 $i$ 行和第 $p_i$ 列不能再有障碍被钦定" 且 ”$(i,p_i)$ 不能被经过“，换言之，我们所“钦定” 的，都是那些 $p_i = -1$ 的位置，对于已经确定的 $p_i$，我们只是把它当成一个确定的障碍，不将其纳入容斥的部分。

设一共有 $m$ 个位置满足 $p_i = -1$。

那么就容易设出状态 $dp[i][j][k][0/1][0/1]$ 表示当前走到了 $(i,j)$ ，一共钦定了 $k$ 个障碍的方案数之和。（后面两个 $0/1$ 表示第 $i$ 行与第 $j$ 列是否已经被钦定过了障碍。

那么分类讨论 $(i,j)$ 处钦定障碍或不钦定障碍转移即可。

最后的答案是 $\sum_{i=0}^m dp[n + 1][n + 1][i][0][0] (m - i)!$。

上文中 $(-1)^t$ 的容斥系数在 DP 转移中顺带处理了。

```cpp
#include <bits/stdc++.h>
using namespace std;
const int N = 2e2 + 5,P = 998244353;
inline void Plus(int &x,const int &y) { x += y;if(x >= P) x -= P;}
int f[N][N][N][4];
int n,p[N],fac[N],num = 0,vst[N];
int main()
{
	cin >> n;
	for(int i = 1;i <= n;i++) 
		cin >> p[i],num += p[i] == -1;
	for(int i = 1;i <= n;i++)
		if(p[i] != -1) vst[p[i]] = true;
	p[n + 1] = -1;
	for(int i = 0;i <= n + 1;i++)
		f[0][i][0][0] = f[i][0][0][0] = 1;
	for(int i = 1;i <= n + 1;i++)
		for(int j = 1;j <= n + 1;j++)
			for(int k = 0;k <= min(i,j);k++)
			{
				if(p[i] != j) // (i,j) 不放障碍
				{
					Plus(f[i][j][k][1],f[i - 1][j][k][1]);
					Plus(f[i][j][k][1],f[i - 1][j][k][3]);

					Plus(f[i][j][k][2],f[i][j - 1][k][2]);
					Plus(f[i][j][k][2],f[i][j - 1][k][3]);

					Plus(f[i][j][k][0],f[i - 1][j][k][0]);
					Plus(f[i][j][k][0],f[i - 1][j][k][2]);
					Plus(f[i][j][k][0],f[i][j - 1][k][0]);
					Plus(f[i][j][k][0],f[i][j - 1][k][1]);
				}	
				if((p[i] == -1) && !vst[j] && k) //(i,j) 放障碍
				{
					Plus(f[i][j][k][3],P - f[i - 1][j][k - 1][0]);
					Plus(f[i][j][k][3],P - f[i - 1][j][k - 1][2]);
					Plus(f[i][j][k][3],P - f[i][j - 1][k - 1][0]);
					Plus(f[i][j][k][3],P - f[i][j - 1][k - 1][1]);
				}
			}
	fac[0] = 1;
	for(int i = 1;i <= n;i++) fac[i] = 1ll * fac[i - 1] * i % P;
	int ans = 0;
	for(int k = 0;k <= num;k++)
	{
		int res = f[n + 1][n + 1][k][0];
		Plus(ans,1ll * res * fac[num - k] % P);
	}
	cout << ans << endl;
	return 0;
}
```

总的来说，这是道计数练手好题。

事实证明卡住的地方比我预想的要弱智一些，构思的时候已经想到了均摊，但对 border 的变化规律似乎缺乏更深的理解，也对最值相关缺乏研究，导致没有想到另一个均摊。

<!--more-->

当然，这题也带来一个直觉，就是 border 相关的工程一般比较轻量级。

第一眼是 border 的四种求法中的 SAM，后来发现显然不用这么复杂，考虑 KMP 的过程即可。

注意到一个前缀的所有  border 是 KMP 失配树上的一条祖先链。想借此维护，但变化量看上去并不小，主要是 $nxt[i]$ 变为 $nxt[i - 1] + 1$ 的时候，可能接上了一条完全不同的祖先链，然后就卡在这儿了。

但事实上，我们直接考虑每个 border 串，在加入一个字符之后，它要么长度也加 $1$，要么就不是 border 串了。

注意到处理完上述变化之后，最多只会有一个长度为 $1$ 的 border 串新加入进来（因为剩下的 border 串都是由上一轮的 border 整体加 $1$ 而来）。

所以删除操作可以暴力执行，我们可以找到每个要删除的 border 串，然后更新相应的信息。

那么如何快速找到那些要删除的 border 串呢。

之前说过，一个前缀的所有 border 是失配树上的祖先链，也就是 $nxt_i,nxt_{nxt_i},\dots,0$，我们对于每个 $i$，维护最深的一个后继字符与它不同的祖先 $anc[i]$，即满足 $s[i + 1] != s[anc[i] + 1] $ 的最深的点。在遍历祖先的过程中，使用 $anc[i]$ 加速即可。

至于 border 串长整体 $+1$ 怎么做，设当前加入了 $n$ 个字符，考察一个长度为 $l$ 的 $border$ 串，它的区间从加入前的 $[n - l + 1,n - 1]$ 变为了 $[n - l + 1,n]$，我们发现，对于这些串，它们的权值只是对当前加入的 $w_n$ 取了个 $\min$。

那么现在就是要维护一堆数，支持对所有数取 $\min$ 和维护和。

我们可以用 map 维护每种权值的出现次数，要对 $w_i$ 取 $\min$ 时，把比 $w_i$ 大的权值都直接变为 $w_i$ 即可。

考察 map 中不同元素个数的变化情况，容易证明这里的均摊复杂度是 $\Theta(n \log n)$ 的。

所以总时间复杂度是 $\Theta(n \log n)$ 的。

```cpp
#include <bits/stdc++.h>
using namespace std;
template<typename T>
inline void write(const T &a)
{
	if(a >= 10) write(a / 10);
	putchar(a % 10 + '0');
}
const int N = 6e5 + 5,MASK = (1 << 30) - 1;
typedef long long ll;
typedef __int128 lll;
int n;
int w[N],s[N];
int stk[N],top;
map<int,int> mp;
int nxt[N];
ll ans;
lll lastans;
int anc[N]; // 第一个后继字符与其不同的祖先，找到那些被删除的 border
inline int Qpos(int pos)
{
	return w[*lower_bound(stk + 1,stk + top + 1,pos)];
}
int main()
{
	cin >> n;
	int j = 0;
	nxt[1] = 0;
	char ch;
	cin >> ch >> w[1];
	s[1] = ch - 'a';
	lastans = w[1];
	stk[++top] = 1;
	write(lastans);
	putchar('\n');
	for(int i = 2;i <= n;i++)
	{
		char ch;
		cin >> ch >> w[i];ch -= 'a';
		w[i] ^= lastans & MASK;
		s[i] = (ch + lastans) % 26;
		while(j && s[i] != s[j + 1]) j = nxt[j];
		if(s[i] == s[j + 1]) ++j;
		nxt[i] = j;
		if(s[i] == s[nxt[i - 1] + 1]) anc[i - 1] = anc[nxt[i - 1]];
		else anc[i - 1] = nxt[i - 1];
		for(int k = i - 1;k;)
		{
			if(s[k + 1] == s[i]) k = anc[k];
			else
			{
				int val = Qpos(i - k);
				--mp[val];
				if(mp[val] == 0) mp.erase(val);
				ans -= val;
				k = nxt[k];
			}
		}
		if(s[1] == s[i])
			++mp[w[i]],ans += w[i];
		while(top && w[stk[top]] >= w[i])
			--top;
		stk[++top] = i;
		int num = 0;
		auto it = mp.upper_bound(w[i]);
		while(it != mp.end())
		{
			num += it -> second;
			ans -= 1ll * (it -> first - w[i]) * it -> second;
			mp.erase(it);
			it = mp.upper_bound(w[i]);
		}
		mp[w[i]] += num;
		lastans += w[stk[1]] + ans;
		write(lastans);
		putchar('\n');
	}
	return 0;
}
```

这是一道总结 border 变化规律和最值变化规律的好题，对向后加入字符的问题，border 有比较简明的变化方式；对很多数不断地 $\operatorname{chkmin}$，也可以使用均摊复杂度做到优秀的结果。

